INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8103777','Під хрест Твій стаю','Музика: В. Стех Слова: о. В. Стех. Виконує: Теотокос','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Під хрест Твій стаю,
Спасителю мій милий,
І молю тебе, подай же мені       |
За гріхи жаль щирий.             | (2)

За мене терпиш,
За мене розп''явся,
За гріхи мої, провину мою        |
Убитись ти дався.                | (2)

О, Ісусе ти мій,
Твої безмірні муки
Кличуть вони нас, взивають усіх  |
До Твоєї любови.                 | (2)

О, і рани твої,
Хоча без уст і мови,
Сильніше від сліз, взивають мене |
До жалю покути.                  | (2)

Подай же мені
Про них все пам''ятати,
Любити тебе, боятись гріха,      |
Тебе прославляти!                | (2)','["pisni.org.ua", "cat:cerkovni", "cat:christian", "cat:narodni", "cat:strasni", "Церковні пісні", "Пісні на християнську тематику", "Народні пісні", "Страсні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8103777'), datetime('now')),datetime('now'));
