INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8113676','Ой, не жалуй, моя мила, що я п''ю','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'http://www.karpaty.lviv.ua, джерело матеріалу: Малова-Малкович П. М. "З карпатських джерел": фольклорно-етнографічеий нарис. - Чернівці: Місто, 2004. - 176 с.',NULL,'Ой, не жалуй, моя мила, що я п''ю,
Тогди будеш жалувати, як я вмру.

Тогди будеш жалувати, плакати,
Як я буду в темнім гробі лежати.

Ой, зазнаєш, моя мила, гаразди,
Як то тяжко в світі жити без ґазди.

Треба хліба, треба соли до хати,
Нема кому бідній вдові встарати.

- Ой, уставай, мій миленький, встань, серце,
Стоїть твоя горівочка та й винце.

- Ой, пий, мила, чорнобрива, пий сама,
Чому-с мені не давала за життя?','["pisni.org.ua", "cat:socialno-pobutovi", "Соціально-побутові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8113676'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8113676','Ой, не жалуй, моя мила, що я п''ю','Ой, не жалуй, моя мила, що я п''ю,
Тогди будеш жалувати, як я вмру.

Тогди будеш жалувати, плакати,
Як я буду в темнім гробі лежати.

Ой, зазнаєш, моя мила, гаразди,
Як то тяжко в світі жити без ґазди.

Треба хліба, треба соли до хати,
Нема кому бідній вдові встарати.

- Ой, уставай, мій миленький, встань, серце,
Стоїть твоя горівочка та й винце.

- Ой, пий, мила, чорнобрива, пий сама,
Чому-с мені не давала за життя?');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8113654','Ой, летіли гуси з далекого краю','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'http://www.karpaty.lviv.ua, джерело матеріалу: Малова-Малкович П. М. "З карпатських джерел": фольклорно-етнографічеий нарис. - Чернівці: Місто, 2004. - 176 с.',NULL,'Ой, летіли гуси з далекого краю,
Сколотили воду на тихім Дунаю.
Одні колотили, другі говорили:
- Мусить война бути, бо вже йдуть рекрути.

Вийшла стара мати на високу гору,
Кличе свого сина із войська додому:
- Ой, ти мій синочку, ходи додомочку,
Най я тобі змию ще раз головочку.

- Тогди-с мені мила, як я був при тобі,
Тепер ми не змиєш, бо я жовняр собі.
Змиють мені, змиють пани капітани,
Тепер ми не треба ні тата, ні мами.

Змиють мені, змиють пани офіцири,
Тепер ми не треба жадної родини.
Змиють мені, змиють дощі майовії,
Кучері розчешуть вітри буйненькії.','["pisni.org.ua", "cat:rekrutski", "Рекрутські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8113654'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8113654','Ой, летіли гуси з далекого краю','Ой, летіли гуси з далекого краю,
Сколотили воду на тихім Дунаю.
Одні колотили, другі говорили:
- Мусить война бути, бо вже йдуть рекрути.

Вийшла стара мати на високу гору,
Кличе свого сина із войська додому:
- Ой, ти мій синочку, ходи додомочку,
Най я тобі змию ще раз головочку.

- Тогди-с мені мила, як я був при тобі,
Тепер ми не змиєш, бо я жовняр собі.
Змиють мені, змиють пани капітани,
Тепер ми не треба ні тата, ні мами.

Змиють мені, змиють пани офіцири,
Тепер ми не треба жадної родини.
Змиють мені, змиють дощі майовії,
Кучері розчешуть вітри буйненькії.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8104950','Швачка та Бондаренко','Українська народна пісня. Виконує: Григорій Китастий','uk','ukraine_before_1917',NULL,NULL,'надав Роман Туровський-Савчук',NULL,'Гей, хвалився та козак Швачка
Під Білую Церкву ідучи:
"Гей, будем, брати, та китайку драти,
Та в онучах топтати".

Гей, казав єси, козак Бондаренко,
А що славонька буде:
Гей, будем, брати, та поли драти,
Та плечі латати...

Гей, на козаченьків, гей, на молоденьких
Та пригодонька спала:
Гей, що в середу та ввечері
Та усіх Москва побрала.

Ой, побрали тай попарували
Усіх по два до курочки -
Зглядаються один на другого,
Як сизії голубочки.

Ой, побрали тай попарували,
Тай повезли возами:
"Ой, оглянемся на ту Україну,
Тай обіллємся сльозами"','["pisni.org.ua", "cat:istorychni", "cat:kozacki", "Історичні пісні", "Козацькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8104950'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8104950','Швачка та Бондаренко','Гей, хвалився та козак Швачка
Під Білую Церкву ідучи:
"Гей, будем, брати, та китайку драти,
