INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_810910','Україна. Рок-н-рол *','(Моя Україна). Слова: Зеновій Филипчук. Виконує: Віка Врадій','uk','ukraine_1991',NULL,NULL,'Пісневир: Молодіжний співаник.— Львів, 2001',NULL,'Я також вже маю державу, і вільно живу, і щасливо.
Я тиждень працюю на каву, два тижні працюю на пиво.
Піду і позичу в сусіда на свята вина і хлібину.
Забули коли добре їли, а, бачите, ще не зомліли.

Приспів:
Моя Україна з горя почорніла,
Тяжко заробляє, але ще співає
Рок-н-рол!

Не треба мені говорити, як добре живеться у Штатах.
Я знаю — двері відкриті, там наших лишилось багато.
Дощі заливають гайвеї, птахи відлітають із дому.
Не знаю, чи зможу без неї навіть в раю золотому.

Приспів:
Моя Україна з горя почорніла,
Але у неділю сорочина біла.
Моя Україна з горя почорніла,
Тяжко заробляє, але ще співає
Рок-н-рол!','["pisni.org.ua", "cat:emigration", "Пісні про еміґрацію"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_810910'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_810910','Україна. Рок-н-рол *','Я також вже маю державу, і вільно живу, і щасливо.
Я тиждень працюю на каву, два тижні працюю на пиво.
Піду і позичу в сусіда на свята вина і хлібину.
Забули коли добре їли, а, бачите, ще не зомліли.

Приспів:
Моя Україна з горя почорніла,
Тяжко заробляє, але ще співає
Рок-н-рол!

Не треба мені говорити, як добре живеться у Штатах.
Я знаю — двері відкриті, там наших лишилось багато.
Дощі заливають гайвеї, птахи відлітають із дому.
Не знаю, чи зможу без неї навіть в раю золотому.

Приспів:
Моя Україна з горя почорніла,
Але у неділю сорочина біла.
Моя Україна з горя почорніла,
Тяжко заробляє, але ще співає
Рок-н-рол!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_810603','Будьмо!','Музика: Ярослав Теплий Слова: Ярослав Теплий. Виконує: Дует "Червоне та чорне"','uk','ukraine_1991',NULL,NULL,NULL,'Дует "ЧЕРВОНЕ ТА ЧОРНЕ", аудіоальбом "ЛЕМКІВСЬКЕ ВЕСІЛЛЯ-2" www.lemky.iatp.org.ua','Зібралось товариство шановне за столом,
Зібралося з нагоди, із хлібом і вином.
Не бачились ми тижні, а може і роки,
Тож дякуємо Богу, що знову разом ми.

Приспів:
Будьмо ж! Гей!
Будьмо! Гей!
Будьмо! Гей!Гей!Гей!-
Шануймося, браття!
Будьмо ж! Гей!
Будьмо! Гей!
Будьмо! Гей!Гей!Гей!-
Бо ми того варті!
Будьмо ж! Гей!
Будьмо! Гей!
Будьмо! Гей!Гей!Гей!-
Хай з нами прибуде!
Будьмо ж! Гей!
Будьмо! Гей!
Будьмо! Гей!Гей!Гей!-
Як будем ми,
То Україна буде!

Зібрались в дружнім колі всі рідні і близькі.
Благословенні будьмо, бо рід у нас такий!
Хай не вмирає Віра, Надію маєм знов;
Хай квітне Україна, і хай живе Любов!

Приспів.','["pisni.org.ua", "cat:bardivski", "Бардівські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_810603'), datetime('now')),datetime('now'));
