INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_81154','Та ти, дівко, подівочиш...','Українська народна пісня. Виконує: Чорні черешні','uk','ukraine_before_1917',NULL,NULL,'Збірник пісень Студентського братства Львівської політехніки.- Львів, 2000','Очевидно, даний варіант, надрукований у текстовому джерелі [1], був записаний упорядниками (знаю їх особисто) з пам''яті, а первісним джерелом був аудіозапис гурту "Чорні черешні". У вказаному джерелі останньої строфи немає, а замість неї повторено першу строфу. Текст потребує більш детального уточнення, бо в аудіо-оригіналі тут є діалектні слова, які важко було точно записати на слух. Отже, маємо тут приблизний варіант тексту, частково адаптований до сучасної української літературної мови. *Тут і далі замість "мій чабане милий", може співатися: "мий чабане, мий-мий".','Та ти, дівко, подівочиш, а я полегіню.
Та й будем си побирати на святу неділю.

На тім боці Дунаю, мій чабане милий*,
Чабан вівці завертав. Гопта-дріта-гойя!

Чабан вівці завертав, мій чабане милий,
Та й до хлопців закликав. Гопта-дріта-гойя!

Ой ви, хлопці-молодці, мій чабане милий,
Та скажіть тій дівочці. Гопта-дріта-гойя!

Най мя, най мя не ждає, мій чабане милий,
Най ся скоро оддає. Гопта-дріта-гойя!

Як то дівка зачула, мій чабане милий,
Та й до мамки махнула. Гопта-дріта-гойя!

Мамко ж моя солодка, мій чабане милий,
Вже мя чабан полишив. Гопта-дріта-гойя!

Копай, дівко, кореня, мій чабане милий,
Та з-під того каменя. Гопта-дріта-гойя!

Не вкопала, лиш оден, мій чабане милий,
Носила ''го на руці. Гопта-дріта-гойя!

Носила ''го на руці, мій чабане милий,
Польокала в потоці. Гопта-дріта-гойя!

Польокала в потоці, мій чабане милий,
Варила ''го в молоці. Гопта-дріта-гойя!

Польокала в потоці, мій чабане милий,
Варила ''го в молоці. Гопта-дріта-гойя!

Єще корінь не скипів, мій чабане милий,
А вже чабан прилетів.  Гопта-дріта-гойя!

А що ж тебе принесло, мій чабане милий,
Ци кучія, ци весло? Гопта-дріта-гойя!

Мене приніс сивий кунь, мій чабане милий,
Бо ти моя, а я твуй. Гопта-дріта-гойя!

Чотири би писарики не переписали,
Що ми з свойов миленькою перещебетали.','["pisni.org.ua", "cat:zakarpatski", "Закарпатські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_81154'), datetime('now')),datetime('now'));
