INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8114116','Без тебе, Олесю','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Українські пісні з нотами. Збірник перший / упорядник П.Ф. Бунт, В. Шаравський. Київ. Видавниче товариство "Час", 1929.',NULL,'Без тебе, Олесю, буйний вітер віє,
Без тебе, голубонько, сонечко не гріє.

Приспів:
Як день, так ніч - то рве душу,
Я до тебе прийти мушу.
Хоча й не раненько,
Олесю, серденько.

Без тебе, Олесю, марно літа гинуть,
До тебе, голубонько, всяк час думки линуть.

Приспів.

Жили ж ми з тобою, як голубів пара,
Тепер розійшлися, як чорная хмара.

Приспів.','["pisni.org.ua", "cat:rekrutski", "Рекрутські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8114116'), datetime('now')),datetime('now'));
