INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_810611','В яслах лежить',NULL,'uk','ukraine_before_1917',NULL,NULL,'Отці Василіани',NULL,'В яслах лежить, хто ж поспішить
Співати маленькому
Ісусу Христу, Богу істу
Новонарожденному.
Пастиріє прибігайте,
Йому мило пригравайте
Яко пану нашому.

Святий Йосиф в руках носить
Пелени Маленькому,
"Люляй, люляй" - приспівує
Новонарожденному;
Віл і осел приклякають,
Паров Його огрівають,
Створителя свойого.

Зібралися, кланялися
Дитятку маленькому,
Тріє царі несуть дари
Новонародженому;
А звіздар їх проводжає,
Над вертепом просвічає,
Де Дитя в яслах лежить.

І Ангели, Архангели
Вдячно всі приспівають,
Голосами і трубами
В небі всі пригрівають:
Над вертепом в Вифлеємі,
В Давидовім тихім домі,
Яко Пану нашому.

Людіє, всі Патріархи -
Всі ся десь утішають,
І отроки со пророки
Согасно воспівають:
Сонце, місцяць со звіз дами,
І ти, Єво, со Адамом,
Нині розвеселіться.

І ви, гори, і ви, холми,
Всі ся десь возіграйте!
І ви, птиці, ви, пірнаті,
Радісно позлітайте,
Бог ізволив народитись,
З Пречистої воплотитись
Присно Діви Марії.

І ми нині всі вірнії,
Всі ся десь утішаймо,
Рож денному безсмертному
Низько ся поклоняймо,
Котрому честь і хвала,
І на віки віків слава,
Яко Пану нашому.','["pisni.org.ua", "cat:kolyadky", "Колядки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_810611'), datetime('now')),datetime('now'));
