INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8117705','Ой ти, Іване, попів, попів','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Пісні Шевченкового краю. Записи, впорядкування і примітки Олекси Ошуркевича. Луцьк: Волинська обласна друкарня, 2006. - 484 с.',NULL,'Ой ти, Іване, попів,
