INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8116817','Воли ж половії','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Українські пісні з нотами. Збірник перший / упорядник П.Ф. Бунт, В. Шаравський. Київ. Видавниче товариство "Час", 1929.',NULL,'Воли ж мої половії,
Ой, чого ж ви помарніли? (2)

Ой, того ж ми помарніли,
Нас хазяїн не жаліє. (2)

Пізно ляже, рано встає,
Бере ярма, нариває. (2)

Бере ярма, нариває,
