INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8116052','Не топила, не варила','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Українські пісні з нотами. Збірник перший / упорядник П.Ф. Бунт, В. Шаравський. Київ. Видавниче товариство "Час", 1929.',NULL,'Не топила, не варила,
На припічку жар, жар,
Як піду я з цього села,
Комусь буде жаль, жаль.

Не топила, не варила,
На припічку димно,
Як піду я з цього села,
Комусь буде дивно.

Не топила, не варила,
На припічку попіл,
Як я піду з цього села,
Зостанеться сокіл...

Не топила, не варила,
На припічку каша:
Прощавайте, сусідоньки,
Тепер я не ваша.','["pisni.org.ua", "cat:socialno-pobutovi", "Соціально-побутові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8116052'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8116052','Не топила, не варила','Не топила, не варила,
На припічку жар, жар,
Як піду я з цього села,
Комусь буде жаль, жаль.

Не топила, не варила,
