INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8118450','Пісня сотні Бурлаки','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,NULL,'Співаник УПА. Борці за волю України. упор. О.Бобикевич, Ю.Лаврівський, О.Плешкевич та ін. Львів: Меморіал. 1992. - 190 с.',NULL,'Не страшна нам є атака,
Як ти з нами наш Бурлака.
Кожний наступ нам приємний,
Як ти з нами наш сотенний.

Приспів:
Гей, чи на бункри, чи на шанці,
Гей, ми в бою, мов би в танці.
Усе ціло вийдем з бою
За твоєю головою.

А як прийде відпочати,
"Фасон тримай пане брате",
Там з дівчатами "чловєку"
Не вдавайся за далеко.

Приспів.

Про дівчат все пам''ятайте
І добре їх забавляйте,
Щоб вороги їх не брали
І лиха їм не завдавали.

Приспів.

"Пане брате" таки вміло,
В селі гідно, в бою сміло,
Щоб усі це пам''ятали,
Кк повстанці воювали.

Приспів.','["pisni.org.ua", "cat:himny-marshi", "cat:povstanski", "Гимни та марші", "Повстанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8118450'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8118450','Пісня сотні Бурлаки','Не страшна нам є атака,
Як ти з нами наш Бурлака.
Кожний наступ нам приємний,
