INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8116676','Ой, там за Дунаєм крутим бережком','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Українські пісні з нотами. Збірник перший / упорядник П.Ф. Бунт, В. Шаравський. Київ. Видавниче товариство "Час", 1929.',NULL,'Ой, там за Дунаєм крутим бережком
Ой, там розмовляє сокіл з козаком:

"Ой, ти, соколоньку, ти братіку мій,
Чи не був ти брате, в моїй стороні.

Чи не був ти брате, в моїй стороні,
Чи плаче, чи туже дівча по мені?"

- Не плаче, не туже, у ліжку лежить,
Правою рукою за серце держить".

Ой, прилетів сокіл та й сів на вікні:
"Добрий вечір, дівчино, приніс тобі вість -
Уже твій миленький у подвір''ї єсть".

Ой, дівчина встала, як і не лежала,
Восковії свічі посвічувала.

"Горіть, горіть, свічі вдень і вночі,
Нехай я надивлюсь милому в очі.

Де ж ти, мій милий, у дорозі був,
Що ти, мій миленький, з личенька змарнів?"

"Через тебе, дівчино, впав я в сухоти,
Ані вночі спання, ані вдень роботи.

Очі б може й спали, та ноги несуть,
Викохав дівчину, та люде беруть."','["pisni.org.ua", "cat:kozacki", "Козацькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8116676'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8116676','Ой, там за Дунаєм крутим бережком','Ой, там за Дунаєм крутим бережком
