INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8118777','На Вавилонських ріках',NULL,'uk','ukraine_1991',NULL,NULL,'http://www.bazylianie.pl/mlolytownyk/pisni.htm',NULL,'На Вавилонських ріках,
