INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_811950','Вгору прапор!','Слова: Віра Лебедова','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,NULL,NULL,'Високо стяг наш піднесім,
Прапор наш малиновий,
Ставаймо в гурт усі при нім
До бою всі готові.

Хто хоче щастя, свободи,
У кого орла крила,
До нас у Січ, до нас в ряди,
У злуці міць і сила.

Як скріпне тіло й дух зросте,
Могутньою Січ стане,
Колишня слава оживе,
Рабства пірвем кайдани.

Сини катованих батьків,
Під стяги Січовії!
Не зломлять зєднаних борців
Ворожих сил затії.

У карних кадрах наша рать
Готова щохвилини
Боротися, життя віддать
Для щастя України.

І щастя те добудем ми
Роками трудів, бою,
Щоб наших нащадків сини
Втішалися свободою.','["pisni.org.ua", "cat:strilecki", "Стрілецькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_811950'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_811950','Вгору прапор!','Високо стяг наш піднесім,
Прапор наш малиновий,
Ставаймо в гурт усі при нім
До бою всі готові.

Хто хоче щастя, свободи,
У кого орла крила,
До нас у Січ, до нас в ряди,
У злуці міць і сила.

Як скріпне тіло й дух зросте,
Могутньою Січ стане,
Колишня слава оживе,
Рабства пірвем кайдани.

Сини катованих батьків,
Під стяги Січовії!
Не зломлять зєднаних борців
Ворожих сил затії.

У карних кадрах наша рать
Готова щохвилини
Боротися, життя віддать
Для щастя України.

І щастя те добудем ми
Роками трудів, бою,
Щоб наших нащадків сини
Втішалися свободою.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8118171','Базар','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,NULL,'Співаник УПА. Борці за волю України. упор. О.Бобикевич, Ю.Лаврівський, О.Плешкевич та ін. Львів: Меморіал. 1992. - 190 с.',NULL,'Як олень той, що загнаний в болото,
Зацькований собаками в лісах,
Боролися там відділи піхоти,
Кіннота йде за ними по слідах...

Паде з утоми військо по дорозі,
Не в силі кріса вдержати в руках,
А босі ноги пухнуть на морозі,
Кривавлять рани в драних сорочках.

І бій кипів... І сил вже не ставало,
За полком полк ішов ворожих сил...
І крикнув хтось: "У нас нема набоїв!"
Зполудня втихло і впав останній стріл.

Загнали їх, забрали від них зброю —
Вірних синів святої боротьби.
І впав наказ: "Ви власною рукою
Копайте тут самі собі гроби!"

Потомлені, знеможені, побиті,
Копали враз могили на полях...
Під оклик, гомін, крик несамовитий
Московських військ, все стало у рядах.

"Готова вже могила всім єдина" —
Промовили. А відповідь дав кат:
"Ось вам Соборна Вільна Україна,
Для вас нема, соборників, пощад!"

"А коли хтось із вас складе присягу,
Що буде вірним вік-по-вік Москві,
І відречеться нині свого стягу,
Той буде вільний і щаслив тоді".

В холодну днину серед снігу, мряки,
Над сніжним гробом, що на них чекав,
Мовчало триста шістдесят юнаків,
Ніхто не зрадив, ласки не благав.

І впав наказ, клекочуть скоростріли,
Юнацтво стелиться мов та трава,
І труп за трупом падає в могилу,
А скоростріл клекоче не вгава.

З великої некритої ще ями
Несуться зойки ранених і зов.
І хтось грозив кривавими руками;
"Ми нині гинем, завтра кров — за кров!"

Хтось вечером закопував могилу,
І бачив, як один стрілець вмирав,
І говорив до другого на силу,
Ти смертію життя народу дав.

Пливуть роки від року, аж до року,
Співає пісню все новий кобзар,
І оспівує у піснях народу
Кривавий, ще не помщений Базар.','["pisni.org.ua", "cat:istorychni", "cat:povstanski", "Історичні пісні", "Повстанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8118171'), datetime('now')),datetime('now'));
