INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_812116','Ой вербиченько','Музика: Ігор Шамо Слова: Любов Забашта','uk','ukraine_1991',NULL,NULL,'1. Пісні солов''їні. Пісенник. — К.: Держ. в-во образотв. м-ва і муз. літ-ри, 1962. — 144 с.',NULL,'Ой вербиченько,
Біле личенько,
Ти шовкова сон-трава,
Пройду отавами,        |
