INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_812575','А в Куцівці Церкву будують','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Староукраїнські Колядки і Щедрівки: Святе Різдво (Свято Різдва Світа: Свят-Вечір – Коляда)... Щедрий Вечір (Свято Місяця й Прадіда: Новий Рік ― Святі Водорщі)... Великдень... Зелені Свята (Трійця)... Івана Купала Сам Біг Небесний Службоньку служит. Службоньку служив Слізоньку вронив. А в Тому Дунаю та Господь купався. А в Горі в Горі в Глибокім Зворі А в Куцівці Церкву будують А в Нашого Дядька да в Його Дому В Бору в Бору да Волохи поють Ой в Бару Бару Валохи гудуть По Конец Стола сидит Никола Святая Варвара Церков будовала Сидїв Никола по Конец Стола Сьвитий Николай став Коло Стола Сидять Кравци да й на Лавочціе Славен єс Боже по всему Сьвіту У Пана Івана да за Його Сталом Ходит походит Місяць по Небі Чи є чи нема Пан Сподар в Дома Чи є чи нема Господар в Дома Три Гискри впало Три Морі стало. НАСПІВ: для 1-ї в''язки: "Звуковий листок для 1 і 2 голосу (відміна 1)"; для 2-ї і наступних в''язок: "Звуковий листок для 1 і 2 голосу (відміна 2)". ДЖЕРЕЛА: Різдвяна Ніч (кружало). Колядки і Щедрівки. Співають Трійця "Либідь" і Олександр Гаркавий. Євшан, 1992. — Різдвяна Книжечка. Видавництво Р. Геррозе. Ґрефенгайніхен. 1944. 31с. — Сосенко Ксенофонт. Культурно-історична постать Староукраїнськиx Свят Різдва і Щедрого Вечора. Львів, 1928. – СІНТО, Київ 1994. 343с. Ідея Почину Світа і його Творця. Колядки як Міти про Почин Світа, Первовічне життя. Староукраїнські Колядки означуються в першій мірі всі як культово-реліґійні, з кількома відмінами реліґійного шанування відповідно до культурно-історичного розвитку Українського народу. Та основою цього шанування є ідея Почину Світа і його Творця. Для того всі Українські Колядки можна означити як Міти про Почин Світа і Первовічне людське життя. Тому то і традиції про первісне господарське й суспільне життя народу містяться в Колядках. (1) А в Куцівці Церкву будують — Колядки пояснюють, що Церква — то весь світ, і в цій Церкві-Всесвіті за "попа", священика, — сам Господь Біг. Він, або Божа Матір, служить службу божу людям. Люди беруть участь у цій службі як послушники і як родина. Кожен тішиться і веселиться своєю інакшістю та різноманітністю світу. Всіх людей об''єднує Бог одним Світом, в одній Церкві, в одній духовній родині. Він є товаришем і Астральних Світил і людей. Така Староукраїнська засада "Світу-Церкви" та ідеальне поняття реліґії як зв''язку з Богом у вселюдській родині є прикладом правдивого універсалізму та екуменізму, коли люди об''єднуються в різноманітності, коли не просто терплять, не тільки визнають одне одного, а й радіють інакшості іншого. Інший — це рідний, а не чужий. До якої б церковної ієрархії не залічували себе люди, всі вони належать до тієї самої Божої Церкви - Всесвіту, до одного, але багатовимірного духовного світу. Давня Правдонька Старих Людей: любов рідні. Присвячуючи стільки уваги етно-культурним порухам Українського племінного Святочного Збору, не можна поминути одного поруху, що був колись першою побудкою цих зборових, гуртуючих і об''єднуючих прагнень. А є він у Святовечірніх обрядах і піснях виразно зазначений та усім народом зберіганий і плеканий. Цим порухом є любов рідні, що поширюється на як найдальші родинні круги, а відтак на усе рідне плем''я. На це було вказано при розгляді обрядів Святої Вечері і оцю ідею любови рідні підносять Колядки. Вона є суттю тої " Давної Правдоньки Старих Людей ", за котрою Колядки тужать. Ой уся Правда тепер погасла. Плач Сокола і Купіль. Тому вони вимріюють взірцеву-досконалу сім''ю — Господаря й Господиню враз з Діточками, — малюючи майже в кожній Колядці чудові образці сімейного щастя. Кожну Колядку кінчать Колядники, "Божі Служеньки", побажанням взірцевих-досконалих сімейних взаємин. Рідня в любови як Святість, Боже улюблене місце. Рідня в злагоді-гармонії й любові — це Святість, це Боже улюблене місце; тому на збірну Святу Вечерю прибувають Небесні Гості — сам Господь посеред Небесного блиску, Місяць і Сонце й усе Небо Йому товаришать, або прикрашують Його стать. Буде в Тебе Господь на Вечері. Ой пошли Боже сьому Хазяїну у Дому Долю (2) Єсть Ти Світ Божий днесь народив..(ся)! — У цьому приспіві поєднується Староукраїнська традиція Різдва Світа: Світ як Син Божий, бо сотворений Господом, — і християнська: народження Сина Божого, Ісуса Христа. Також — Світ Божий як Радість і Світло (неоднозначність слова "Світ"). Радість, Вдяка і Слава Богу. Отся загальна, неповинна, дитиняча радість, яку об''являє матір з діточками, криє в собі поезію загальної радості усієї Божої твари в містичну добу Сотворення Світа. Святий Вечер — сеж година перед досвітком Всесвіта — і після думки народу, як людина, так звірина, птиця і мушка повинні дати вираз радості і вдяки перед Творцем за своє життя. А святкуючі рільники і скотарі не повинні в отсю годину забувати, що уся тая домашня худібка, — приятелі, помічники й кормильці родини, — сотворені від Бога Творця людям на радість, Йому на славу і вдяку. Див. Свято Радості. Святий Збір і Радість: Бог в Астральній красі та славі. Тай начала щебетати Господаря викликати. Рай розвився Господь звеселився! У тім вибухові життя-радості на Свят-Вечер, у сій потребі виявлення щасливих почувань серед сім''ї і в бажанні втягнути до того усе, що живе, криється як-раз глибока ідея Свята Різдва. А без сумніву сплітаються тут зараз обидві ідеології ― старовіцька й християнська. Нарід дуже справно узгодив Первовічну пісню Всесвіта з радісними піснями про народження Спасителя Ісуса Христа. Є багато більше складових у Святім Вечері, порозкиданих, непов''язаних, на перший погляд незрозумілих. Та всі вони знаходять вияснення у Колядках та Щедрівках. Багато там є нового, самостійного, і не вираженого ясно в поведінках Святовечірніх. Цілий світ Старовіцьких ідей. Хто Колядок і Щедрівок не знає, той не вгадає Святочних душевних мріянь Українського народу. (3) (Що)А в Перше віконце вскочило Сонце — Астральна Трійця як символ Астрального Вогню. Господь, Вогонь і Вода. Ідея наглядно виступає — Вогонь як животворна Троїста Сила, будить життєве тепло у Всесвіті і рівночасно покликує до дії творчу Воду. Сам Господь у тій Воді купається — така вона свіжа й животворча. Мабуть чи не сам Господь є символом того Первовічного Вогню і навпаки — Вогонь символом Господа (ідея відома з мітольоґії світової і біблійної). В кожнім разі на цих сполучених двох Первовічних елементах стає "Престіл" Божої слави й основа благословенства Божого людям. Пане Господаре на Твоїм Двору Ялина стоїть (4) А в Третє віконце улетів Янгол — Відміни: улетів Сокіл, або увійшла Зоря. Містична Купіль Господа. В Колядках містична Купіль Господа приносить світові щастя і добро. Це є Первовічна містерія, — благословенні цією Купіллю Води служать до освіження й обнови Новонародженого Світа (Часу), наче поправляють його хиби й недостачі та запобігають недолі народу. Сокіл (або Янгол, або Святий) виплакав у Бога Добру Долю людям. Еротичні містерії, тиждень від Катерини 7.12 до Калети: Колядки про Долю. Доля як Божий дар. Ой пошли Боже сьому Хазяїну у Дому Долю. В інших Колядках сказано, що Господь плаче прийшовши між нарід і з його Сліз творяться животворні Води. Ім''я Господа буває в Колядках синонімом Христа, Спасителя світа, що визволяє людей від вічної недолі. В цей спосіб стається Сокіл в очах народу алегоричною поставою Спасителя навіть при християнськім світогляді. (5) А з Тієї Сльози та Дунай розлився Спогади про Праводу та життєві ідеали. Український нарід лучить із Святоріздвяними спогадами про Праводу цілий світ своїх життєвих ідеалів, що їх сподіється здійснити при містичній чудотворній помочі тої Води, через яку стався увесь Світ. Її Сила і Святість немов степенується в Святочнім часі від Різдва до Богоявління (Водорщів) та доходить до зеніту в великій містерії Водорщів. Майже кожна Колядка й Щедрівка нагадує народові про мітичні, незглубимі таїнниці світових Вод. Богу молився щоб Світ творився Коляди у Гуцулів: народ — не бики. Станїславівский владика був остро виступив перед кількома роками против наших звичєїв колєдницких и против наших колєд, кажучі: "То поганцкий звичєй колєди! А шє такі, єк ту у вас на Гуцулах колєди, то вже цїлком ни хрестіянскі, а ті ваші звичєї то безбожні, єкі ви виробєєте в колєдниках". — Заборонив остро попам пускати колєдники після нашего давного звичю, лиш аби ишли так, єк туда на долах дес кажут, шо ходє колєдуючі, отєк буком молотїчі, з одної хати раз два до другої. Попи и так ни дуже були до наших гуцулских звичів добрі и дивили си кривим оком на нашу моду, а тепер єк дав їм владика потуку, то вни вже цїлком гадали, шо вже все перевернут з окрашем. Але то гов! Нарид ни бики, звичь, обрєд старовіцкий — то ни мітуса. Заказали попи на Риздво, отєк ни поледви з почєтком 1907 року, ити колєдникам з набутками. Заказали скрипку, тримбіту, плєс, гулянє на колониї й співанки гуцулскі — одним словом кажучі сказали, аби ходили по церковному, побожно, так єк ходє колєдники по долах. Господи, шо то си завів за рейвах, най лиш Бих борони. Зачєли всї люде говорити, шо то вже попи хотє віру скасувати нашу давну, бо в нас говорє так, шо доки писанки пишут и доки колєдники ходє, то доти и наша віра руска буде на світї. В деєких селах цїлком си сперли люде ити колєдувати на церкву, а пишли колєдувати після стародавного звичю, але на свіцкі цїли. Знов в деєких селах попи боєли си дразнити людий и мало шо сперали, а порештї пустили після гуцулского звичю говорєчі: "Идїт, єк собі хочете, то нас ни обходи, бо ми вам ни позволєємо жєдних набутків". — Але колєдники на це ни фівкали, лиш робили своє. Єк ходили після давних звичєїв, так ходє й тепер, лиш ни вид дуже давного чєсу в деєких селах скасували колєду брати, то є, хлїб й зерно, а то через то, шо говорєт, шо тепер тєжкі чєси, доста й гроший на колєду... Миколая. Вже вид Ників зачінают люде прирєхтовувати си до колєдників. Кождий ревір збераєт ци, шо май фрунтові ґазди й впливові у тим кутї и вадиковуют мижи собов бирше менче, ци мают ити колєдники, котрий береза має ити в їх бик й здебирше котрі колєдники. Знов усеймовуют собі, де си мают зберати колєдники и в єким порєдку мают ити вид хати до хати, та де має бути розплєс колєдницкий. Звичєйно тогди на Николи є дві противні партії людий. Одни є за колєдниками, а знов є й такі шо вни є против колєдників. Ни одни є мижи противниками й такі, шо сами би ради ити в колєдниках, але шо вни до колєдників низдалі, або їх люде нинавидє и через то їх ни берут нїколи, а їм за се кривда и тимунь вни адикуют проти колєди, але однако инчими шпітаками, бо прилучюют ци до скупиндрясив, шо шкодуют пара корон на кошт; а знов єк идут вже колєдники, то їм ни випадат ни приймати колєдників и тимунь говорє проти колєдників отими бирше менче словами: "Тепер всєка біда нам доста вже доколєдовує, на шо нам колєдників? То все драчя, кошт па громаду. Пип казав нам нираз, шо то би бирший був хосен, єк би ти гроші люде добровилно без колєди зложєли до церкви, шо би хто втєкав дати. То би красше було. А так то ни колєди, але гріхи"! Та однако звичєйно прихєльників колєдницких є бирше и перекричюют противників, бо нираз и до острих сварок приходи мижи одними и другими. ІІрихєльники говорє: "Гі на вас! Устидайте си! Ви ни хочєте вже того, шо сми диждали, шо обходили наші дєдї й предїди. Нам вилно колєдувати, на шо ми хочємо, а ни кончє гроші обертати на церкву. Нам тут пип ни до розказу, але ми сами. Єк ни идут колєдники, то за шо, тай на шо нїс бих гроші попови? Ми в колєдники будим ити, тай будим пускати, тай приймати так, єк доси; ни збіднїли сми тим до тепер, тай чій ни пидим в старцї й вид тепер, ійга! Та тілько ходь маємо веселости в серци! А хто нинавиди на колєдники, або єму ни рихт, то най ни приймає, а про него си обийде, бо колєдники мают доста коло кого ходити". Майже завжде вже по службі на Николи всї си помирє и хотє колєдники пускати. Понайменовуют собі березив, аби на Риздво ни бути сміхом, а берези борше пидмаґулюют собі котре себнїшших колєдників, щоби їх табора була єк найдобирнїйшя. Кілька ґазд з села входє','А в Куцівці Церкву будують

