INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8122052','Ой щіт-щіт!','Музика: народ Слова: народ','uk','ukraine_1991',NULL,NULL,'З пам''яті','Жартівлива, танцювальна.','Ой, щіт-щіт, ой, щіт-щіт!
Щітка маленька
Та на камінечку сиділа-сиділа.
Не пищіт, не пищіт,
Бо почує ненька!
Та дрібний мачок
Дзьобала-дзьобала.

