INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8126552','Школа моя','Музика: Леся Соболевська Слова: Леся Соболевська. Виконує: Зоряна Рощук','uk','ukraine_1991',NULL,NULL,NULL,NULL,'1.
Вересень знову нам казку пряде,
Cm         B7      Es C7
Кленом стежину встеляє
Fm        B7        Es      As
Ту, що до школи нас знову веде
Срібний дзвіночок лунає.

Приспів:
Школа моя - мій найперший дзвінок,
Cm     Fm          B7      Es
Школа моя - мій найкращий урок.
Лагідна вчителька входить у клас,
Ddim                 D7 G7  Cm
Та, що в життя проводжатиме нас.

2.
Сонячні зайчики скачуть у клас,
Cm    B7       Es C7
Осені барви багряні
Fm       B7        Es        As
Нам нагадають - до школи вже час,
Бо вже сумують за нами.

Приспів.

3.
Осінь тихенько іде по землі,
Cm       B7      Es C7
Вересом сипле довкола.
Fm     B7     Es       As
Літо минуло і ми підросли.
А чи впізнає нас школа?..

Приспів','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8126552'), datetime('now')),datetime('now'));
