INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_812272','Ми йдем вперед','Музика: Лев Лепкий Слова: Лев Лепкий. Виконує: Тарас Чубай, Плач Єремії','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'CD "Тарас Чубай і Скрябін. "Наші партизани". 2000','Проект "Наші Партизани" Два останні рядки кожного куплету - двічі. Інший варіант акордів (для нижчого голосу): | G Em C D | x2 | G E7 Am | D G | x2 Підбір акордів: bohdanko','Ми йдем вперід. Над нами вітер віє,
І рідні нам вклоняються жита.
Від радости аж серце млі-і-є.
За волю смерть нам не страшна!
Ми йдем вперед. Над нами сонце сяє.
Гармати б''ють, здригається земля.
І гордість грудь аж розпирає.
За волю смерть нам не страшна!
Ми йдем вперед. Здалека чути гуки.
Гармати б''ють, і крові всюди вщерть.
Не буде більш терпінь, ні муки!
Вперед! - Там воля або смерть!
Дзвенять шаблі, як ясне сонце, сяють,
Гримлять пісні, аж земленька свята
Дрожить під нами дорогая.
За волю смерть нам не страшна!
Ми йдем вперед. Над нами вітер віє,
І рідні нам вклоняються жита.
Від радости аж серце мліє.
За волю смерть нам не страшна!','["pisni.org.ua", "cat:patriotic", "cat:povstanski", "cat:strilecki", "Патріотичні пісні", "Повстанські пісні", "Стрілецькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_812272'), datetime('now')),datetime('now'));
