INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_812878','Не плачте не журіться','Українська народна пісня. Виконує: Тарас Чубай, Плач Єремії','uk','ukr_ssr_1919_1991',NULL,NULL,'текст- Літопис УПА. 1996-1997.– Т.25: Пісні УПА; CD- Тарас Чубай і Скрябін. "Наші партизани". 2000','Підбір акордів: bohdanko','Вступ:  C A#*  (4)

C          A#*        C 	G   C
Не плачте не журіться ви хлопці юнаки
C          A#*       C     G     C
бо незабаром прийде ще бранка на дівки, -
розберем всіх до нага, як Еви у раю    |
і так їх попровадим перед комісію.     |

Програш:  F C    (2)
C A#*  (2)

Котра дівчина гарна і легка мов той птах,
то та буде служити напевно в літаках,
якщо хто буде важить сто кіля із дівчат, *  | (2)
то та піде служити до танків і гармат.      |

Котра дівчина гарна, а не впорядку все,
то та дістане книжку, а в ній велике "Ц".
розберем всіх до нага, як Еви у раю       | (3)
і так їх попровадим перед комісію.        |

* В джерелі:
Котра дівчина важить сто кіля із дівчат.

Акорд A#* [x 1 0 3 3 x] - можна не брати.','["pisni.org.ua", "cat:povstanski", "cat:zhartivlyvi", "Повстанські пісні", "Жартівливі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_812878'), datetime('now')),datetime('now'));
