INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8128205','Зайчики','(У лісі, лісі темному). Музика: Леонід Бекман Слова: Іван Нехода. Виконує: Механічний Апельсин','uk','ukraine_before_1917',NULL,'1903','Мене навчили цієї пісні у дитячому садочку у Львові у 1950-і роки.','Український варіант написаний за мотивами російської пісні "В лесу родилась елочка" на текст вірша "Ёлка" Раїси Кудашової (1903) на музику Леоніда Бекмана (1905).','У лісі, лісі темному,
Де ходить хитрий лис,
Росла собі ялиночка
І зайчик з нею ріс.

Ой, снігу, снігу білого
Насипала зима.
Прибіг сховатись заїнько -
Ялиноньки нема!

Їшов тим лісом Дід Мороз,
Червоний в нього ніс,
Він зайчика-стрибайчика
У торбі нам приніс.

Маленький сірий заїнько,
Іди-іди до нас!
Дивись - твоя ялиночка
Сія на весь палац!','["pisni.org.ua", "cat:dytyachi", "Дитячі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8128205'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8128205','Зайчики','У лісі, лісі темному,
Де ходить хитрий лис,
Росла собі ялиночка
І зайчик з нею ріс.

Ой, снігу, снігу білого
Насипала зима.
Прибіг сховатись заїнько -
Ялиноньки нема!

Їшов тим лісом Дід Мороз,
Червоний в нього ніс,
Він зайчика-стрибайчика
У торбі нам приніс.

Маленький сірий заїнько,
Іди-іди до нас!
Дивись - твоя ялиночка
Сія на весь палац!');
