INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8126575','Раз я сиділа біля віконця',NULL,'uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Раз я сиділа біля віконця,
Біля відкритого вікна
До мене циганка,
Циганка молодая
Аж під віконце підійшла

Дай ми дівчино свою рученьку
Хай я тобі поворожу
Хоч я циганка, хоч я молодая
Всю щиру правду розкажу

Ти маєш хлопця, хлопця молодого
Він п''є горівку, мед вино
Він грає в карти в карти виграває
Про тебе вже забув давно.

Ой як він може про мене забути
Коли портрет той на стіні
Ой як він може про мене забути
Коли дитина на руці.

Портрет той викінь через віконце
Дитину в дітсадок віддай
А сама іди, іди між дівчата
Іншого милого шукай','["pisni.org.ua", "cat:lirychni", "Пісні про кохання, ліричні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8126575'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8126575','Раз я сиділа біля віконця','Раз я сиділа біля віконця,
Біля відкритого вікна
До мене циганка,
Циганка молодая
Аж під віконце підійшла

Дай ми дівчино свою рученьку
Хай я тобі поворожу
Хоч я циганка, хоч я молодая
Всю щиру правду розкажу

Ти маєш хлопця, хлопця молодого
Він п''є горівку, мед вино
Він грає в карти в карти виграває
Про тебе вже забув давно.

Ой як він може про мене забути
Коли портрет той на стіні
Ой як він може про мене забути
Коли дитина на руці.

Портрет той викінь через віконце
Дитину в дітсадок віддай
А сама іди, іди між дівчата
Іншого милого шукай');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8127307','На Дніпрі','Музика: Журборіз Слова: Володимир Скоробський. Виконує: Журборіз','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'На Дніпрі, як на Дніпрі,
Вітер, хвиля у човни
Посідали, заспівали:
Гей, гук, мати, гук,
Де козаки йдуть.

Стерновий тримає вітер,
Щогла скрикне, затиха.
Молодому пластунові
Пісня душу рве, гей, ма!
Гей, ма, гей, ма!
Пісня душу рве, гей, ма.
Гей, ма, гей, ма!
Пісня душу рве, гей, ма.

Промах хвилю розрізає,
Дніпр, Славута рве дарма,
Стерновий все налягає,
Отаман співа: гей, га!
Гей, ма, гей, ма!
Отаман співа: гей, га!
Гей, ма, гей, ма!
Отаман співа: гей, га!

І журбою пісня лине,
Попід кручі вздовж Дніпра,
Сміх і радість щохвилини
На байдаках недарма.
Гей, ма, гей, ма!
На байдаках недарма.
Гей, ма, гей, ма!
На байдаках недарма.

Славні прадіди великі
Спадок лишили нам свій,
То пісенна Україна
По Дніпрі іде, радій!

Батьку Орлію і Тарасе,
Батьку Хмелю і святі,
Старсилавські князі наші,
Руські-вої, козаки.
Гей, ма, гей, ма!
Руські-воїни, козаки.
Гей, ма, гей, ма!
Руські-вої, козаки.

Славні стрільці січовії
І повстанськії орли,
По Дніпрі байдаки риють,
Лине пісня на Дніпрі.
Гей, ма, гей, ма!
Лине пісня на Дніпрі.
Гей, ма, гей, ма!
Лине пісня на Дніпрі.

Помолились Миколаю,
Посідали в байдаки,
Руна берегом лунає:
Гей, гук, мати, гук,
Де козаки йдуть.
Гей, ма, гей, ма!
Стерновий все наляга,
Отаман співа: гей, га...
Гей, ма, гей, ма!
Отаман співа: гей, га...
Гей, ма, гей, ма!
Отаман співа: гей, га...','["pisni.org.ua", "cat:istorychni", "Історичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8127307'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8127307','На Дніпрі','На Дніпрі, як на Дніпрі,
Вітер, хвиля у човни
Посідали, заспівали:
Гей, гук, мати, гук,
Де козаки йдуть.

Стерновий тримає вітер,
Щогла скрикне, затиха.
Молодому пластунові
Пісня душу рве, гей, ма!
Гей, ма, гей, ма!
Пісня душу рве, гей, ма.
Гей, ма, гей, ма!
Пісня душу рве, гей, ма.

Промах хвилю розрізає,
Дніпр, Славута рве дарма,
Стерновий все налягає,
Отаман співа: гей, га!
Гей, ма, гей, ма!
Отаман співа: гей, га!
Гей, ма, гей, ма!
Отаман співа: гей, га!

І журбою пісня лине,
Попід кручі вздовж Дніпра,
Сміх і радість щохвилини
На байдаках недарма.
Гей, ма, гей, ма!
На байдаках недарма.
Гей, ма, гей, ма!
На байдаках недарма.

Славні прадіди великі
Спадок лишили нам свій,
То пісенна Україна
По Дніпрі іде, радій!

Батьку Орлію і Тарасе,
Батьку Хмелю і святі,
Старсилавські князі наші,
Руські-вої, козаки.
Гей, ма, гей, ма!
Руські-воїни, козаки.
Гей, ма, гей, ма!
Руські-вої, козаки.

Славні стрільці січовії
І повстанськії орли,
По Дніпрі байдаки риють,
Лине пісня на Дніпрі.
Гей, ма, гей, ма!
Лине пісня на Дніпрі.
Гей, ма, гей, ма!
Лине пісня на Дніпрі.

Помолились Миколаю,
Посідали в байдаки,
Руна берегом лунає:
Гей, гук, мати, гук,
Де козаки йдуть.
Гей, ма, гей, ма!
Стерновий все наляга,
Отаман співа: гей, га...
Гей, ма, гей, ма!
Отаман співа: гей, га...
Гей, ма, гей, ма!
Отаман співа: гей, га...');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_812552','У райськім саду','(Яворина). Музика: Степан Гіга Слова: Степан Галябарда. Виконує: Степан Гіга','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Я на світі прожив, наче спалах зорі на світанні,
Наче крапля роси, наче крик журавля - тільки мить.
Я не вірив ніяк, що й до мене прийде день останній,
І в жертовнім вогні моє серце на попіл згорить.
Я ж так щедро кохав, я так вірив у зорі і очі,
І душею своєю я вас, як умів, причащав.
Але видно Господь мені краще життя напророчив,
І до себе забрав, щоб у райськім саду я співав.
Приспів:
На могилі моїй посадіть молоду яворину,
І не плачте за мною, за мною заплаче рідня.
Я любив вас усіх, та найбільше любив Україну,
Певно, в цьому і є та найважча провина моя.
Хай душа переселиться в дивний той рай потойбічний,
Де таких, як і я, назліталася ціла сім''я.
Тільки нащо мені ті блаженства розкішні і вічні,
Як мені не всміхнеться донька-сиротинка моя.
У далеких світах якось раптом усе я покину,
Бо ввійде мені в душу сльозиною і чебрецем,
І додому хоч вітром, хоч променем сонця полину,
І легенько війну над твоїм, Україно, лицем.
Приспів.','["pisni.org.ua", "cat:devoted", "cat:nostalgia", "Пісні присвячені окремим особам", "Пісні з ностальгічними мотивами"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_812552'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_812552','У райськім саду','Я на світі прожив, наче спалах зорі на світанні,
