INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_813013','Ой, зацвіла папороть','Музика: В. Верховинець Слова: М. Хвильовий','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'"Молоде життя", Ауґсбурґ, 1949.',NULL,'Ой, зацвіла папороть, зацвіла,
На Купала, в темряву між дерев.

А у лісі шелестом лісовик
Прокидає шелести і жахи.

Як хочеться, хочеться взяти скарб -
Ті червінці блискавки під ліском -

В позолоту кралею уквітчать
Те життя сучаснеє, що скиглить.

Ой, зацвіла папороть, зацвіла,
Та не в казці жити нам, а в борні!','["pisni.org.ua", "cat:strilecki", "Стрілецькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_813013'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_813013','Ой, зацвіла папороть','Ой, зацвіла папороть, зацвіла,
На Купала, в темряву між дерев.

А у лісі шелестом лісовик
Прокидає шелести і жахи.

Як хочеться, хочеться взяти скарб -
Ті червінці блискавки під ліском -

В позолоту кралею уквітчать
Те життя сучаснеє, що скиглить.

Ой, зацвіла папороть, зацвіла,
Та не в казці жити нам, а в борні!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8129858','Дай мені руку','Музика: Олександр Шевченко Слова: Олександр Шевченко. Виконує: Олександр Шевченко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'День за днем, за роком рік минає,
Їх мені уже не наздогнати,
Шкода, що ми часто забуваєм
Тих, кого не можна забувати.
Тільки тим і треба дорожити,
Хто з тобою і в біді, і в тузі,
Лиш тоді на світі варто жити,
Поки є ще в тебе справжні друзі.

Приспів:
Пісня ця нехай до них полине,
Розтривожить спогадами душу,
Хай поверне молодості днину,
Дай мені руку, друже,
Дай мені руку, друже!

Знову після зустрічі розлука,
Вирушаю я в дорогу дальню,
Завтра ми візьмемося за руку,
Пісню заспіваємо прощальну.
І коли ми разом заспіваєм,
Пісню цю ніхто вже не задушить,
Хай горить вогонь і не згорає.
Дай мені руку, друже!

Приспів.

Друзів моїх, бачу обличчя,
Чую їх голос, чую їх сміх,
Друзів моїх піснею кличу, |
Друзів моїх, друзів моїх. | (2)','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8129858'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8129858','Дай мені руку','День за днем, за роком рік минає,
