INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8131501','Ах, Українонько','Українська народна пісня. Виконує: Лайош Молнар','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ах, Українонько,
Бідна годинонька тепер твоя:
Згинули козаки,             |
Добрії юнаки, ах, кров моя. | (2)

Где ж ви, Дорошенки,
Где ж ви, Хмельниченки, і ви, Івани,
Смілії сотники, битні десятники,
І ви, гетьмани?

Як много поганців
З наших же бранців — діток малих?
З них тепер татарів,        |
З них яничарів маєм своїх.  | (2)

Ах, Українонько,
Бідна годинонька тепер твоя...','["pisni.org.ua", "cat:istorychni", "Історичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8131501'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8131501','Ах, Українонько','Ах, Українонько,
