INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_8131501_l1','pisniua_8131501','YouTube','https://www.youtube.com/watch?v=GOYR_jt7P3U','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8130171','Романс для Вас','Музика: Мар''ян Гаденко Слова: Ганна Чубач. Виконує: Іван Красовський','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Я сьогодні признаюся Вам,
Що душа на спогади багата,
Замовляю музику в словах,
Замовляю успіх на відплату.
Замовляю квіти на рояль
І розмову поміж нами,
Вічну радість і одвічний жаль
Я для Вас не викажу словами.

Замовляю небо у зірках,
Теплий вечір також замовляю,
Хай Ваш голос і мої слова
В ніжній пісні поруч спочивають.
Хай пливе мелодія легка,
Як туман, над бистрою рікою,
Хай тремтить на клавішах рука
Від звучання музики такої.

Пригадаю все, що відбуло,
Доєднаю все, що є сьогодні.
Я клянуся небом і крилом -
Ви мені відмовити не годні.
Я сьогодні признаюся Вам,
Що душа на спогади багата,
Замовляю музику в словах,   |
Замовляю успіх на відплату. | (2)','["pisni.org.ua", "cat:romansy", "Романси"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8130171'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8130171','Романс для Вас','Я сьогодні признаюся Вам,
Що душа на спогади багата,
Замовляю музику в словах,
Замовляю успіх на відплату.
