INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_8130171_l1','pisniua_8130171','YouTube','https://www.youtube.com/watch?v=tSjJ20Q6whM','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_813001','Карпатські січовики','Музика: Григорій Китастий Слова: Яр Славутич','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'"Молоде життя", Ауґсбурґ, 1949.',NULL,'То не лист осінній за водою
По шикорій Тисі проплива, -
Багрянить за хвилею крутою
Підкарпатська буйна голова.

Бились хлопці Хустові на славу,
Полягли в нерівному бою
За свою омріяну державу,
Січовую воленьку свою.

І пливуть до тихого Дунаю -
Мов на турка - браття в байдаках.
Синя хвиля жалібно гойдає,
Течія показує їм шлях.

Буде сліз, та не збороти горю
Ні батьків, ні в тузі матерів.
Чорне море, українське море,
Зустрічай своїм багатирів!','["pisni.org.ua", "cat:istorychni", "cat:strilecki", "Історичні пісні", "Стрілецькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_813001'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_813001','Карпатські січовики','То не лист осінній за водою
По шикорій Тисі проплива, -
Багрянить за хвилею крутою
Підкарпатська буйна голова.

Бились хлопці Хустові на славу,
Полягли в нерівному бою
За свою омріяну державу,
Січовую воленьку свою.

І пливуть до тихого Дунаю -
Мов на турка - браття в байдаках.
Синя хвиля жалібно гойдає,
Течія показує їм шлях.

Буде сліз, та не збороти горю
Ні батьків, ні в тузі матерів.
Чорне море, українське море,
Зустрічай своїм багатирів!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8128219','Через ліс, через ліс','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Цю пісню співають у нас в сім''ях',NULL,'Через ліс, через ліс
Треба нам, малята,
Щоб грибів, щоб грибів
В лісі назбирати.

На місточку вовчик спочиває,
Він до лісу діток не пускає.

Він гарчить, він гарчить,
Клацає зубами:
Не пущу, не пущу
Діток за грибами!

Вийшов козлик з зеленого гаю,
Він сердито вовчику гукає:

Заколю, заколю
Я тебе рогами,
Затопчу, затопчу
Я тебе ногами!

Як ударив вовчика рогами -
покотився вовчик в воду прямо!

Ми йдемо, ми йдемо
Мостом через річку,
Несемо, несемо
Козлику травичку:

Ой, спасибі, козлику рогатий,
Що поміг нам вовчика прогнати!','["pisni.org.ua", "cat:dytyachi", "cat:zhartivlyvi", "Дитячі пісні", "Жартівливі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8128219'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8128219','Через ліс, через ліс','Через ліс, через ліс
Треба нам, малята,
Щоб грибів, щоб грибів
В лісі назбирати.

На місточку вовчик спочиває,
Він до лісу діток не пускає.

Він гарчить, він гарчить,
Клацає зубами:
Не пущу, не пущу
Діток за грибами!

Вийшов козлик з зеленого гаю,
Він сердито вовчику гукає:

Заколю, заколю
Я тебе рогами,
Затопчу, затопчу
Я тебе ногами!

Як ударив вовчика рогами -
покотився вовчик в воду прямо!

Ми йдемо, ми йдемо
Мостом через річку,
Несемо, несемо
Козлику травичку:

Ой, спасибі, козлику рогатий,
Що поміг нам вовчика прогнати!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_8128219_l1','pisniua_8128219','YouTube','https://www.youtube.com/watch?v=dd1fq5pqGQc','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8131817','Цвітіння раннє','Музика: Ліля Кобільник Слова: Марія Матіос. Виконує: Ліля Кобільник','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ти дав мені цвітіння раннє,
У тебе літо на порі,
Про наші місячні блукання
Хіба що знають глухарі
Та ще цвіркунчики у травах.

Лиш ніч під місяцем нага,
Хтось і ступить не мають права
Ні слово, ні людська нога.

Та освятить оце кохання
Хіба що можуть глухарі,
Ти дав мені цвітіння раннє,
У тебе літо на порі, на порі,
На порі...','["pisni.org.ua", "cat:romansy", "Романси"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8131817'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8131817','Цвітіння раннє','Ти дав мені цвітіння раннє,
У тебе літо на порі,
Про наші місячні блукання
Хіба що знають глухарі
Та ще цвіркунчики у травах.

Лиш ніч під місяцем нага,
Хтось і ступить не мають права
Ні слово, ні людська нога.

Та освятить оце кохання
Хіба що можуть глухарі,
Ти дав мені цвітіння раннє,
У тебе літо на порі, на порі,
На порі...');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8131518','Кант про Почаївську Божу матір','Українська народна пісня. Виконує: Лайош Молнар','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой зійшла зоря вечоровая,
Над Почаївом стала,
Виступало турецькеє військо,
Як та чорна хмара.

Турки з татарми брами облягали,
Товсті стіни розбивали,
Ой, в кого ж нам рятунку шукати?
Треба погибати.

Отець Залізо з келії вийшов,
Слізьми умиває,
Ой, рятуй, рятуй, Божая Матір,
Монастир загибає.

Ой, вийшла, вийшла Божая Матір
Та на хресті вона стала,
Стріли ворогів повертала,
Монастир рятувала.','["pisni.org.ua", "cat:istorychni", "Історичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8131518'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8131518','Кант про Почаївську Божу матір','Ой зійшла зоря вечоровая,
Над Почаївом стала,
Виступало турецькеє військо,
Як та чорна хмара.

Турки з татарми брами облягали,
Товсті стіни розбивали,
Ой, в кого ж нам рятунку шукати?
Треба погибати.

Отець Залізо з келії вийшов,
Слізьми умиває,
Ой, рятуй, рятуй, Божая Матір,
Монастир загибає.

Ой, вийшла, вийшла Божая Матір
Та на хресті вона стала,
Стріли ворогів повертала,
Монастир рятувала.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_8131518_l1','pisniua_8131518','YouTube','https://www.youtube.com/watch?v=42_QC37U2nI','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8125654','Мете...','Музика: Тризубий Стас Слова: Тризубий Стас. Виконує: Тризубий Стас','uk','ukraine_1991',NULL,NULL,'http://ukrmusic.com.ua',NULL,'Мете...
Вихрить за вікнами, гуде, мете...
Мете...
А на душі — ні се, ні те.
Мете...
А ви, напевно, вже спите, спите...
Ми бачились два тижні.
Ви були такі ніжні...
Тепер те все пусте.

Я вас три місяці не виджу,
Бо я у Львові, ви — в Парижу.
На сторінках "Юманіте"
Друкують ваше декольте.
А в нас мете...

Несе...
На мене вітер білий сніг несе.
Несе мене на "Ладі" по шосе.
Несе...
А на душі моїй — ні те, ні се...
І серце — як лелека,
Бо ви є так далеко...
Набридло те усе!

Та я поїду до Парижу,
Я свою мрію не облишу.
У вас там "парлі ву франсе
І пуркуа, і кес ке се",
А в нас несе...

Жене мене за нею у турне дурне,
Жене у карбюраторі пальне.
Жене...
Невже кохана бортане мене?
Невже мене не прийме
В палкі свої обійми,
А візьме й лажане?...

Та я дістанусь до Парижу,
Нехай на тім зароблю грижу!
І ваше серце крижане
Розтопить пляшка "Каберне", чи "Сам жене"...

Паде...
Автодвірник танцює
Па-де-де...
Паде...
Мабуть, не їду я ніде.
Паде...
О''ревуар, мадам,
Мерсі гранде!
Додому повертаю,
А в мене у сараю
Вже цеглу хтось краде...

Я ще колись буду в Парижу,
Чи, може, там листа напишу.
І, хоч Париж той бозна-де,
Та, може, лист мій і дійде...
... А в нас паде','["pisni.org.ua", "cat:bardivski", "Бардівські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8125654'), datetime('now')),datetime('now'));
