INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_81312','Там попід лісом','Виконує: Буття, Не журись!','uk','ukr_ssr_1919_1991',NULL,NULL,'Пісневир. Молодіжний співаник. Львів 2001.',NULL,'Там попід лісом, темним бором
Повстанці наші йдуть,
І на руках своїх могутніх
Товариша несуть.
І знову хмари потемніли,
А з моря йде туман.
Скажи, скажи, чого задумавсь,
Повстанський отаман?
А той товариш, хлопець бравий,
Повстанець молодий,
Він цілий кров''ю обіллятий,
З розбитими грудьми.
І знову хмари потемніли,
Стріляв наш кулемет,
Комуна боса утікає,
УПА іде вперед!
А як вже вийшли на полянку,
Сказали сотням: "Стань!"
Сказали сотням: "Стань на струнко!"
І: "На могилу глянь!"
І знову хмари потемніли,
А з моря йде туман.
Скажи, скажи, чого задумавсь,
Повстанський отаман?
"Спочинь, наш друже, хлопче бравий,
Відважний, молодий!
Тебе ми з честю поховаєм,
А завтра підем в бій!"
І знову хмари потемніли,
Стріляв наш кулемет,
Комуна боса утікає,
УПА іде вперед!','["pisni.org.ua", "cat:povstanski", "Повстанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_81312'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_81312','Там попід лісом','Там попід лісом, темним бором
Повстанці наші йдуть,
І на руках своїх могутніх
Товариша несуть.
І знову хмари потемніли,
А з моря йде туман.
Скажи, скажи, чого задумавсь,
Повстанський отаман?
А той товариш, хлопець бравий,
Повстанець молодий,
Він цілий кров''ю обіллятий,
З розбитими грудьми.
І знову хмари потемніли,
Стріляв наш кулемет,
Комуна боса утікає,
УПА іде вперед!
А як вже вийшли на полянку,
Сказали сотням: "Стань!"
Сказали сотням: "Стань на струнко!"
І: "На могилу глянь!"
І знову хмари потемніли,
А з моря йде туман.
Скажи, скажи, чого задумавсь,
Повстанський отаман?
"Спочинь, наш друже, хлопче бравий,
Відважний, молодий!
Тебе ми з честю поховаєм,
А завтра підем в бій!"
І знову хмари потемніли,
Стріляв наш кулемет,
Комуна боса утікає,
УПА іде вперед!');
