INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8138116','Чоловік і жінка','Музика: Тризубий Стас Слова: Тризубий Стас. Виконує: Тризубий Стас','uk','ukraine_1991',NULL,NULL,'http://uamusiclib.com',NULL,'Ми усі вивчаєм жінку,
Щоб якось її збагнуть,
Та пробити лобом стінку -
Це реальніше, мабуть.
Це ж якого треба лоба,
Щоб аж синій був від гуль,
І яка б не була спроба,
В результаті маєм нуль.

Розумія всю ту марність,
Чоловік простий, як борщ,
А вона - мінлива хмарність:
То в ній сонце, то в ній дощ,
Загадково-випадкова,
Невловима наче ртуть,
І завжди неоднакова -
Ось така жіноча суть.

Кожен раз вона інакша,
Кожен раз вона нова,
Вдень твердіша, вночі м''якша.
Синусоідна крива.
Це єдина наша втіха,
Й, водночас, суцільний жах,
А тому у чоловіка
З того всього їде дах.

Я також свою вивчаю,
Півжиття разом прожив,
Але щось не помічаю,
Щоб хоч трохи зрозумів.
Це створіння незбагненне,
І перш ніж пробувать вивчать,
Тут потрібно, як на мене,
Академію кінчать.

Та життя мене навчило,
Що робити це дарма,
Бо наука тут безсила -
В них же ж формули нема.
Тож не варто й намагатись,
Все одно, не зрозуміть,
Тут одне - пристосуватись
І біля них, як песик, жить.

І ми несемо свою службу,
І вимахуєм хвостом,
І любов у нас і дружба,
Як в собаки із котом.
Чоловік для них забавка,
А вони - це пуп землі,
Тільки й чуєш: "Цить, не гавкай,
Твоя кістка на столі!"

Жінка нас бере до хати,
Як зручну й корисну річ,
Щоб було кому кохати
Й працювати день і ніч.
А тому іще до шлюбу
Мусит думать чоловік,
Як йому не врізать дубу
Біля них за цілий вік.

Але й жінці треба знати,
Що таке чоловіки,
Перед тим як споживати
Наші здібності тонкі.
Ми складніші за комп''ютер,
Або інший агрегат,
Нас не купиш за валюту
І не візьмеш на прокат.

А тому їм треба вміти
Чоловіка берегти:
Готувати, не сварити,
За горілкою піти.
Акуратно, обережно,
Як дитинку доглядать,
От тоді ми, як належно,
Палко, ніжно і безмежно
Обіцяєм їх кохать.','["pisni.org.ua", "cat:bardivski", "Бардівські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8138116'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8138116','Чоловік і жінка','Ми усі вивчаєм жінку,
Щоб якось її збагнуть,
Та пробити лобом стінку -
Це реальніше, мабуть.
Це ж якого треба лоба,
Щоб аж синій був від гуль,
І яка б не була спроба,
В результаті маєм нуль.

Розумія всю ту марність,
Чоловік простий, як борщ,
А вона - мінлива хмарність:
То в ній сонце, то в ній дощ,
Загадково-випадкова,
Невловима наче ртуть,
І завжди неоднакова -
Ось така жіноча суть.

Кожен раз вона інакша,
Кожен раз вона нова,
Вдень твердіша, вночі м''якша.
Синусоідна крива.
Це єдина наша втіха,
Й, водночас, суцільний жах,
А тому у чоловіка
З того всього їде дах.

Я також свою вивчаю,
Півжиття разом прожив,
Але щось не помічаю,
Щоб хоч трохи зрозумів.
Це створіння незбагненне,
І перш ніж пробувать вивчать,
Тут потрібно, як на мене,
Академію кінчать.

Та життя мене навчило,
Що робити це дарма,
Бо наука тут безсила -
В них же ж формули нема.
Тож не варто й намагатись,
Все одно, не зрозуміть,
Тут одне - пристосуватись
І біля них, як песик, жить.

І ми несемо свою службу,
І вимахуєм хвостом,
І любов у нас і дружба,
Як в собаки із котом.
Чоловік для них забавка,
А вони - це пуп землі,
Тільки й чуєш: "Цить, не гавкай,
Твоя кістка на столі!"

Жінка нас бере до хати,
Як зручну й корисну річ,
Щоб було кому кохати
Й працювати день і ніч.
А тому іще до шлюбу
Мусит думать чоловік,
Як йому не врізать дубу
Біля них за цілий вік.

Але й жінці треба знати,
Що таке чоловіки,
Перед тим як споживати
Наші здібності тонкі.
Ми складніші за комп''ютер,
Або інший агрегат,
Нас не купиш за валюту
І не візьмеш на прокат.

А тому їм треба вміти
Чоловіка берегти:
Готувати, не сварити,
За горілкою піти.
Акуратно, обережно,
Як дитинку доглядать,
От тоді ми, як належно,
Палко, ніжно і безмежно
Обіцяєм їх кохать.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_8138116_l1','pisniua_8138116','YouTube','https://www.youtube.com/watch?v=C2VjU1FfJgc','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_813777','Український рок-н-рол','Слова: Н. Виливок. Виконує: Михайло Поплавський','uk','ukraine_1991',NULL,NULL,'http://www.poplavskiy.com/',NULL,'Я живу! Я співаю!
Україну я кохаю!
Тож навколо подивіться,
Одне одному всміхніться,
Бо життя дається тільки один раз!
Хай навколо все вирує,
Все співає і танцює!
Хай любов перемагає!
Про добробут кожен дбає,
Щоб у нашім домі все було гаразд!
Гей, похмурий перехожий,
Посміхнись, тебе я прошу,
Щоб кругом усе розквітло,
Життя стало наше світлим,
Тож танцюєм
Український рок-н-рол!

Приспів:
Рок, рок, рок-н-рол!
Рок, рок, рок-н-рол!
Рок, рок, рок-н-рол!
Рок, рок, рок-н-рол!
Ми танцюєм
Український рок-н-рол!

Затанцює кум і сват
І народний депутат,
Той, хто добру душу має,
В кого серденько співає!
Затанцюймо, друзі,
З нами всі разом!

Приспів.

Хай життя, як пісня лине,
Все погане хай загине!
Хай розквітне Україна!
Любить парубка дівчина,
Бо життя дається тільки один раз!
Я живу! Я співаю!
Україну я кохаю!
Тож навколо подивіться,
Одне одному всміхніться,
Бо життя дається тільки один раз!
Бо життя дається тільки один раз!','["pisni.org.ua", "cat:suspilno-politychni", "Суспільно-політичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_813777'), datetime('now')),datetime('now'));
