INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8145013','Карпати','Українська народна пісня. Виконує: Наталія Бучинська','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, летять лелеки,
Летять далеко шукати рай.
Я ж лишаюсь вдома,
Бо тут смереки, бо тут мій край!
Тут я рідною мовою,
Наче сни, кольоровою,
Розмовляла з дібровами,
Тут мені дала доля два крила!

Приспів:
Я така крилата, бо росла в Карпатах,
Бо росла в Карпатах, де орел літа!
В мене очі сині, бо на Україні
Сині-сині ночі, небо і вода!
В мене, мов колосся, золоте волосся,
Бо на Україні осінь золота!
Я співаю дзвінко, бо я - українка,
Хто мене не любить, тих мені шкода!

Ой, летять весною лелеки
Знову у рідний край.
Ой, летять додому,
Забувши втому, садів розмай.
Я зустріну їх піснею
Променистою, чистою
Про той край, де з дитинства я
Кожен день пила воду з джерела!

Приспів. (2)','["pisni.org.ua", "cat:krasa-pryrody", "cat:patriotic", "Пісні про красу природи", "Патріотичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8145013'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8145013','Карпати','Ой, летять лелеки,
Летять далеко шукати рай.
Я ж лишаюсь вдома,
Бо тут смереки, бо тут мій край!
Тут я рідною мовою,
Наче сни, кольоровою,
Розмовляла з дібровами,
Тут мені дала доля два крила!

Приспів:
Я така крилата, бо росла в Карпатах,
Бо росла в Карпатах, де орел літа!
В мене очі сині, бо на Україні
Сині-сині ночі, небо і вода!
В мене, мов колосся, золоте волосся,
Бо на Україні осінь золота!
Я співаю дзвінко, бо я - українка,
Хто мене не любить, тих мені шкода!

Ой, летять весною лелеки
Знову у рідний край.
Ой, летять додому,
Забувши втому, садів розмай.
Я зустріну їх піснею
Променистою, чистою
Про той край, де з дитинства я
Кожен день пила воду з джерела!

Приспів. (2)');
