INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_814358','Історія','Музика: Віктор Камінський Слова: Богдан Стельмах. Виконує: Віктор Морозов, Не журись!, Віталій Білоножко, Бандурна Розмова','uk','ukraine_1991',NULL,NULL,'Пісневир: Молодіжний співаник.— Львів, 2001','Автор музики пісні "Історія" - Віктор Камінський, а не Богдан Янівський. (Інформацію про авторство пісні надав Віктор Морозов, http://www.mo-productions.com). Акорди (варіант 2) надав Lubko','Сурми зазоріли, коні одуріли,
Заступили сонце половецькі стріли.
Лічить мати втрати, мила в тузі мліє —
Отака історія в пісні попеліє.

Розлились пожари попід чорні хмари.
Витоптали землю турки-яничари.
Плаче в полі вітер і сліпа бандура —
Отака історія українська дума.

Йшли за кровну справу, здобували славу.
Закотили долю панові під лаву.
На столах у глеках — крові чорні вина.
Отака історія, отака гостина.

Встеклі та запеклі засвітили в пеклі,
Насукали шнурів, пов''язали петлі.
Хто пішов під кулі, хто — в полярне сяйво.
Отака історія, вивчити не зайво.

Димом, порохами поміж реп''яхами,
Дихає Чорнобиль нашими гріхами.
Ті зреклися мови, ті зреклися роду.
Отака історія рідного народу.

Акорди (варіант 2):

Сурми зазоріли,     коні одуріли,
F#m Em            C    Edim               Hm
Заступили сонце      половецькі стріли.
Лічить мати втрати, мила в тузі мліє —
Отака історія в пісні попеліє.

Cm.. (то всьо саме тільки на півтон вище)','["pisni.org.ua", "cat:chornobyl", "cat:istorychni", "Чорнобильська катастрофа: пісні", "Історичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_814358'), datetime('now')),datetime('now'));
