INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8141415','Іванове зілля','Музика: народ Слова: народ. Виконує: Крайня Хата','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Іванове зілля цвіте у Карпатах
У темному лісі, як місяць зійде.
Хто цвіт його зірве, в долоні положить,  |
Той щастя і долю навіки знайде.          | (2)

Іванове зілля, Іванове зілля,
Іванове зілля цвіте один раз.
І так, як весна раз приходить у травах   |
Один раз кохання приходить до нас.       | (2)

