INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8144575','Шукала тебе','Якщо колись заблукаєш в вирі днів,
Свої крила ти не складай.
Згадай усе, що любив,
Двері щастю ти не закривай.
І незважаючи, що у серці біль
Пече, руйнує твоє життя,
Мені повір, і впусти
В змучене серце нові почуття.

