INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8147858','Чудо із чудес','(Алелуя). Музика: В. Кондратюк Слова: В. Кондратюк. Виконує: Руслана','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Чудо, чудо, чудо, чудо із чудес -
Бог післав нам Сина свого із небес!
Чудо, чудо, чудо, чудо сталося,
Бо дитя від Діви народилося! Алелуя!

А чи ви чули, люди, цю новину?
Що у Вифлеємі Діва
Породила сина в бідній стайні,
Бо не знайшлось для неї
Більше місця в Віфлеємі,
Ні в хатині, ні в заїзді.
А час був пізній,
Тож просто в яслах його положила
І пеленами сповила
Ще й сіном притрусила.
А недалеко в полі пастухи були,
Отари свої стерегли нічної пори
Та раптом господній ангел
Серед них явився і сповістив,
Що у Вифлеємі нині Христос родився
І враз на небі сяє сила війська небесна,
І пастухи почули спів чудесний!

Алелуя! Слава вишніх Богу!
Алелуя! І мир на землі!
Алелуя! Людям добра воля! Алелуя!
Чудо, чудо, чудо, чудо із чудес -
Бог післав нам Сина свого із небес!
Чудо, чудо, чудо, чудо сталося -
В небі нова зірка засвітилася! Алелуя!

А чи ви чули, люди, новину?
Що Бог спасіння дарував
Народу своєму,
Що в давнину за різних уст
За різних часів
Пророкували святі Божі
Про народження Месії.
А коли Христос родився -
В небі нова зоря з''явилась
І мудрецям зі Сходу
Радість сповістила,
Вони, співставивши в писанні,
Бачачи зорю,
Прийшли в Іудею поклонитися
Рожденому Царю
Та не з порожніми руками -
До ніг Ісуса щиро принесли свої дари:
Золото, ладан і миру,
Бо їм серце підказало,
Що рождений від Марії
Є спаситель всього світу,
Божий син, Месія!

Алелуя! Слава вишніх Богу!
Алелуя! І мир на землі!
Алелуя! Людям добра воля! Алелуя!
Чудо, чудо, чудо, чудо із чудес -
Бог післав нам Сина свого із небес!
Чудо, чудо, чудо, чудо сталося,
Бо дитя від Діви народилося! Алелуя!
Алелуя! Алелуя! І мир на землі!
Алелуя! Людям добра воля! Алелуя!
Алелуя! Алелуя! Алелуя! Алелуя!','["pisni.org.ua", "cat:shchedrivky", "cat:suchasni-pisni-rizdvo", "Щедрівки", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8147858'), datetime('now')),datetime('now'));
