INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_814807','Вставай вставай не час тепер на сон','Музика: народна Слова: Олександр Олесь','uk','ukr_ssr_1919_1991',NULL,NULL,NULL,'Висловлювання – Народна мудрість: Буду в Січі жить Бога боронить. (Щедрівка)','Вставай-вставай          | (2)
не час тепер на сон.
Мов рана рідний край, мов зойк оден і стон.

Приспів:
Вставай-вставай-вставай, не час тепер на сон.
Мов рана рідний край, мов зойк оден і стон.

Завзялась вража xлань, щоб люд з землі змести,
Куди лиш не поглянь - хрести-xрести-xрести.

Біліє в полі кість, і червониться кров,
І веселиться злість, і сльози ллє любов.

Бездомний чоловік іде в незнаний світ,
А скільки там калік, а скільки там сиріт.

День темний від димів, ніч ясна від вогнів.
А скільки вже тиx днів і ночей у вогні.','["pisni.org.ua", "cat:povstanski", "cat:suspilno-politychni", "Повстанські пісні", "Суспільно-політичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_814807'), datetime('now')),datetime('now'));
