INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8150272','Дума Волоха','Музика: Кирило Стеценко Слова: Тарас Шевченко. Виконує: Борис Гмиря, Павло Кармалюк','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ой, волохи, волохи,
