INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_815256','Гей там у Вільхівці','Музика: Роман Купчинський Слова: Лев Лепкий','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,NULL,'ХХст: Купчинський-Гайворонський Висловлювання — Тарас Шевченко ("До Основ''яненка"): Б''ють пороги Місяць сходить, як і перше сходив, Нема Січі пропав і той, що всім верховодив Нема Січі, очерети у Дніпра питають Де ж то наші діти ділись, де вони гуляють? Не вернуться Запорожці, не встануть Гетьмани Не покриють Україну червоні жупани Тільки ворог щось сміється.','Гей там у Вільхівці там Дівчина живе
Від неї мов од сонця проміння ясне б''є
Сміються карі очі мов зорі серед ночі            |
Від неї мов од сонця проміння ясне б''є           | (2)

До тої Дівчиноньки Хорунжий заходив
І в карих оченятах спокій душі згубив
Чи в хаті чи у полі кляне нещасній долі          |
І в злості дві російські дивізії розбив          | (2)

Аж раз у темну нічку як світ безжурно спав
Таємними стежками москаль на полк напав
Як лев наш Черник бився тай він вкінець зморився |
Разом із товариством в неволеньку попав          | (2)

Тепер він марширує в далекую Сибір
І очі все звертає до ясних ясних зір
А як на зорі гляне він Вільховець спом''яне       |
І дивиться так сумно в синіючу простір           | (2)','["pisni.org.ua", "cat:strilecki", "Стрілецькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_815256'), datetime('now')),datetime('now'));
