INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_815415','Допоможи нам, Боже, домогтись','Слова: Shtyk','uk','ukraine_1991',NULL,NULL,NULL,'Наразі це просто вірш. На музику я ще не положив, але не можу більше тримати його в себе у блокноті... якщо хтось має хист композитора і напише музику раніше мене - я не заперечую.','Народ проснувся вже й не спить,
Він мерзне на вулицях.
У небі хмари грізні зібрались.
Коли вже вдарять блискавиці?

Коли проллється срібний дощ
Щоб змити бруд з тієї влади,
Котра народ мордує мій
Копійки ржавої заради?

Чи буде правда у краю,
Щоби бандити і герої
Всі називались по ім''ю
Не прикриваючися млою?

Щоб тавро злодія було
Поставлено на кожного бандюгу
І щоб сидів він у тюрмі,
А не в парламенті грів дупу.

Щоб помаранчеві герої
Ввійшли в історію святу
Як переможці від народу,
А не як політв''язні на снігу.

Втрачаєм час, втрачаєм мить,
Померзнуть голови гарячі.
Чи розійдуться по хатах
Сьорбать недоїдки свинячі?

Ні! Не підуть вони з майданів
Без перемоги жданої віками.
Всі хочуть жити без кайданів
В Україні, не блукаючи світами.

Допоможи нам, Боже, домогтись
Ідеї вольності і правди
Бо невідомо чи колись
Ще буде шанс такий в громади.','["pisni.org.ua", "cat:bardivski", "Бардівські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_815415'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_815415','Допоможи нам, Боже, домогтись','Народ проснувся вже й не спить,
Він мерзне на вулицях.
У небі хмари грізні зібрались.
Коли вже вдарять блискавиці?

Коли проллється срібний дощ
Щоб змити бруд з тієї влади,
Котра народ мордує мій
Копійки ржавої заради?

Чи буде правда у краю,
Щоби бандити і герої
Всі називались по ім''ю
Не прикриваючися млою?

Щоб тавро злодія було
Поставлено на кожного бандюгу
І щоб сидів він у тюрмі,
А не в парламенті грів дупу.

Щоб помаранчеві герої
Ввійшли в історію святу
Як переможці від народу,
А не як політв''язні на снігу.

Втрачаєм час, втрачаєм мить,
Померзнуть голови гарячі.
Чи розійдуться по хатах
Сьорбать недоїдки свинячі?

Ні! Не підуть вони з майданів
Без перемоги жданої віками.
Всі хочуть жити без кайданів
В Україні, не блукаючи світами.

Допоможи нам, Боже, домогтись
Ідеї вольності і правди
Бо невідомо чи колись
Ще буде шанс такий в громади.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8159103','Пісня про льон','Українська народна пісня. Виконує: Фольклорний ансамбль села Межирич','uk','ukraine_before_1917',NULL,NULL,'Фольклорний архів ансамблю "Божичі". Запис в с.Межирич (Маврино) Павлоградського р-ну Дніпропетровської обл. 12.08.1993 Касета 3',NULL,'Над полями та над нивами
Вітер мається,
Голубими переливами
Льон гойдається.

Льон гойдається, кучерявиться
В голубім краю.
Може взглянеться, зацікавиться
Той кого люблю.

Ждала-ждала свого милого,
Недіждалася.
В тракториста чорнобривого
Закохалася.

Закохалась, тільки глянула
В сині очі, як підійшов,
Недоглянула, як заглянула
В серденько любов.

Зірка з неба полум''яного
Впала птицею,
Я сорочку для коханого
З льону вишию.

Над полями та над нивами
Вітер мається,
Голубими переливами
Льон гойдається','["pisni.org.ua", "cat:arkhiv-bozhychi", "Фольклорний архів анс. \"Божичі\""]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8159103'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8159103','Пісня про льон','Над полями та над нивами
Вітер мається,
Голубими переливами
Льон гойдається.

Льон гойдається, кучерявиться
В голубім краю.
Може взглянеться, зацікавиться
Той кого люблю.

Ждала-ждала свого милого,
Недіждалася.
В тракториста чорнобривого
Закохалася.

Закохалась, тільки глянула
В сині очі, як підійшов,
Недоглянула, як заглянула
В серденько любов.

Зірка з неба полум''яного
Впала птицею,
Я сорочку для коханого
З льону вишию.

Над полями та над нивами
Вітер мається,
Голубими переливами
Льон гойдається');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8160154','Біда','Українська народна пісня. Виконує: Фольклорний ансамбль села Межирич','uk','ukraine_before_1917',NULL,NULL,'З архіву анс. "Божичі"',NULL,'Ой, біда, подруженьки, біда,
А я зовсім дівчина молода.
Полюбила парубка за селом,
А у нього кучері над чолом.

Довго придивлялася я до них,
Де взя такі кучері чарівні.
А за тії кучері над чолом,
Загубила спокій я за селом.

Цілу ніч простояла я до зорі,
Покусали ніженьки комарі,
А за тії кучері над чолом,
Била мене мати батігом.

Не бий мене, матінко, ой, не бий,
Як Василь повернеться буде мій,
Як Василь повернеться на зорі,
Заспокоє серденько він мені.','["pisni.org.ua", "cat:arkhiv-bozhychi", "Фольклорний архів анс. \"Божичі\""]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8160154'), datetime('now')),datetime('now'));
