INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8162409','Межи трьома дорогами','Українська народна пісня. Виконує: Остап Кіндрачук','uk','ukraine_before_1917',NULL,NULL,'Остап Кіндрачук','Старовинна весільна пісня з Волині. Наречений тут "князь" (діал. "кнєзь")','Межи трьома дорогами, рано-рано.
Межи трьома дорогами, ранесенько.

Здибалися князь Дажбог, рано-рано.
Здибалися князь Дажбог, ранесенько.

Ой ти боже, ти Дажбоже, рано-рано.
Ой ти боже, ти Дажбоже, ранесенько.

Зверни ж мені з доріженьки, рано-рано.
Зверни ж мені з доріженьки, ранесенько.

Бо ти богом вік від віку, рано-рано.
Бо ти богом вік від віку, ранесенько.

А я князем раз на віку, рано-рано.
А я князем раз на віку, ранесенько.

Раз на віку в неділеньку, рано-рано.
Раз на віку в неділеньку, ранесенько.

Здибалися князь Дажбог, рано-рано.
Здибалися князь Дажбог, ранесенько.','["pisni.org.ua", "cat:vesilni", "cat:volynski", "Весільні пісні", "Пісні з Волині"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8162409'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8162409','Межи трьома дорогами','Межи трьома дорогами, рано-рано.
Межи трьома дорогами, ранесенько.

Здибалися князь Дажбог, рано-рано.
Здибалися князь Дажбог, ранесенько.

Ой ти боже, ти Дажбоже, рано-рано.
Ой ти боже, ти Дажбоже, ранесенько.

Зверни ж мені з доріженьки, рано-рано.
Зверни ж мені з доріженьки, ранесенько.

Бо ти богом вік від віку, рано-рано.
Бо ти богом вік від віку, ранесенько.

А я князем раз на віку, рано-рано.
А я князем раз на віку, ранесенько.

Раз на віку в неділеньку, рано-рано.
Раз на віку в неділеньку, ранесенько.

Здибалися князь Дажбог, рано-рано.
Здибалися князь Дажбог, ранесенько.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8154307','В''язанка лемківська','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Kulik A., Pleśniak P. Dla Oli na słowiańską nutę. Wybrane pieśni łemkowskie, bojkowskie, słowackie, polskie i inne. - Mińsk Mazowiecki, 2001. – 16 p.',NULL,'Ідемо, ідемо,
Дороги не знаємо,
Добрі люди знають,
То нам повідають.

Ідемо, ідемо
І піском, і ледом,
А чи достанемо
Палянички з медом?

Ідемо, ідемо,
Де дві свічки горять,
Будемо стукати,
А чи нам отворят?

Купила мі мама корову
Та й на мою бідну голову.
Казала мі пасти, доїти,
А я рада з хлопцем ходити.

Казала мі січку різати,
Корову гребінцем чесати,
А корова стара, худорлява,
Бодай она здохла до рана.

А я тоту стару корову,
Зажену її кийом до дому,
Поставлю до стайні стояти,
Сама піду з хлопцем гуляти.

Сидит кітка на полиці
В тій червоній рукавици,
Вистромила оченяти
На ті наши молодята.

З далека ж ми приїхали,
Коні нам ся захлистали.
Треба би нам рушничка
Пообтирати коничка.','["pisni.org.ua", "cat:kolomyyky", "Коломийки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8154307'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8154307','В''язанка лемківська','Ідемо, ідемо,
Дороги не знаємо,
Добрі люди знають,
То нам повідають.

Ідемо, ідемо
І піском, і ледом,
А чи достанемо
Палянички з медом?

Ідемо, ідемо,
Де дві свічки горять,
Будемо стукати,
А чи нам отворят?

Купила мі мама корову
Та й на мою бідну голову.
Казала мі пасти, доїти,
А я рада з хлопцем ходити.

Казала мі січку різати,
Корову гребінцем чесати,
А корова стара, худорлява,
Бодай она здохла до рана.

А я тоту стару корову,
Зажену її кийом до дому,
Поставлю до стайні стояти,
Сама піду з хлопцем гуляти.

Сидит кітка на полиці
В тій червоній рукавици,
Вистромила оченяти
На ті наши молодята.

З далека ж ми приїхали,
Коні нам ся захлистали.
Треба би нам рушничка
Пообтирати коничка.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_816171','Нова радість стала *','Українська народна пісня. Виконує: Ансамбль Львівського Університету "Черемош", Оксана Білозір','uk','ukraine_before_1917',NULL,NULL,'Колядки.- Львів: Каменяр, 1990.- 64 с.','Інші варіанти тексту: * На небесах і на землі мир проповідають. ** І ми теж співаймо, Царя прославляймо. Акорди внесла Natal-ka','(A7)
Нова радість стала, яка не бувала:
Над вертепом звізда ясна світлом засіяла. (2)

Де Христос родився, з Діви воплотився,
Як чоловік пеленами убого повився. (2)

Ангели співають, "слава" восклицають,
На небесах і на земли мир провозглашають. * (2)

Давид виграває, в гуслі ударяє,
Мелодійно і предивно Бога вихваляє.

