INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8163171','Новорічна зоря','Музика: Олег Макаревич. Виконує: Оксана Пекун','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ще блукає між снігів
Довгожданний Рік Новий,
І до нього ще нема
Ні стежок, ані слідів,
Але мріється нам всім,
Що у світ разом із ним
Прийде радість в кожен дім!

Приспів:
Новорічна зоря,
Як блискуча сльоза,
Плаче рік цей старий,
Що прощатись пора.
Ялинкові вогні,
Золоте конфеті,
І здійсняться хай мрії усі!

В казці добрій і старій
Серця замок крижаний
Дружба, вірність і любов
Розтопили жаром мрій,
Наче в казці, у житті
Так трапляється, коли
В щастя палко вірим ми!

Приспів.

Вітер змін і вітер втрат -
Снігу спогадів він брат,
Свого бігу круговерть
Не поверне вже назад.
Серед холоду й біди
Так про щастя мрієм ми
І чекаємо весни!

Приспів. (2)

Здійсняться хай мрії усі!','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8163171'), datetime('now')),datetime('now'));
