INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8160171','Доярка','Українська народна пісня. Виконує: Фольклорний ансамбль села Межирич','uk','ukraine_before_1917',NULL,NULL,'З архіву ансамблю "Божичі"',NULL,'У колгоспі я робила,
Корови доїла,
Умивалась молоком,
Щоб я була біла.

Умивалась молоком
Під дубом зеленим,
Полюбила бригадира
З кучерявим чубом.

Полюбила бригадира
Другої бригади,
А ще треба полюбить
Голову сільради.

Голова сільради
Низенького росту,
Треба мені полюбить
Голову колгоспу.

Прийшла до контори,
Сіла я на лавку:
Товарищу голова,
Дайте мені справку.

Дайте мені справку,
Щоб я була певна,
На роботу не ходила
Й получала прем''я.

А ти, жінко молода,
Іди собі до дому,
Справку дам я тобі,
Не кажи нікому.

Товарищу голова,
Приходь на вечерю,
Я бутилку куплю
Ще й качку печену.

Не приходить голова
На другу бригаду,
Бо розбита голова
З переду і з заду.

Оце тобі, голова,
За чужі учинки,
Щоб ти справку не давав
Для чужої жінки!','["pisni.org.ua", "cat:arkhiv-bozhychi", "cat:socialno-pobutovi", "Фольклорний архів анс. \"Божичі\"", "Соціально-побутові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8160171'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8160171','Доярка','У колгоспі я робила,
Корови доїла,
Умивалась молоком,
Щоб я була біла.

Умивалась молоком
Під дубом зеленим,
Полюбила бригадира
З кучерявим чубом.

Полюбила бригадира
Другої бригади,
А ще треба полюбить
Голову сільради.

Голова сільради
Низенького росту,
Треба мені полюбить
Голову колгоспу.

Прийшла до контори,
Сіла я на лавку:
Товарищу голова,
Дайте мені справку.

Дайте мені справку,
Щоб я була певна,
На роботу не ходила
Й получала прем''я.

А ти, жінко молода,
Іди собі до дому,
Справку дам я тобі,
Не кажи нікому.

Товарищу голова,
Приходь на вечерю,
Я бутилку куплю
Ще й качку печену.

Не приходить голова
На другу бригаду,
Бо розбита голова
З переду і з заду.

Оце тобі, голова,
За чужі учинки,
Щоб ти справку не давав
Для чужої жінки!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8164817','Мамині долоні','Музика: Ігор Іванців Слова: Ольга Климців','uk','ukraine_1991',NULL,NULL,'http://ivantsiv.at.ua',NULL,'Як сідає вечір на порозі хати
Золотистим шовком зорі гаптувати,
Я від зір тих ясних наче у полоні
Заховаю личко в мамині долоні.

В тихій диво-ласці казка розквітає,
Знаю, що дитинство вічним не буває.
І не вічне чудо в золотім озерці,
Лиш любов до мами на весь вік у серці.

Десь на небосхилі тихо зірка сяє,
А мені матуся щастя вишиває.
Ніжність свого серця і любов, тривогу
Стелить злото-шовком місячну дорогу.

Речитатив:
Знаю, де б не був я на стежинах долі,
Будуть гріти душу мамині долоні,
І ласкавий вечір на порозі хати,
Сяде поруч неньки - мене виглядати.','["pisni.org.ua", "cat:pro-batkiv", "Пісні про любов до батьків"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8164817'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8164817','Мамині долоні','Як сідає вечір на порозі хати
Золотистим шовком зорі гаптувати,
Я від зір тих ясних наче у полоні
Заховаю личко в мамині долоні.

В тихій диво-ласці казка розквітає,
Знаю, що дитинство вічним не буває.
І не вічне чудо в золотім озерці,
Лиш любов до мами на весь вік у серці.

Десь на небосхилі тихо зірка сяє,
А мені матуся щастя вишиває.
Ніжність свого серця і любов, тривогу
Стелить злото-шовком місячну дорогу.

Речитатив:
Знаю, де б не був я на стежинах долі,
Будуть гріти душу мамині долоні,
І ласкавий вечір на порозі хати,
Сяде поруч неньки - мене виглядати.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_815705','Не спи, моя рідна земля','Музика: Сергій Фоменко Слова: Сергій Фоменко. Виконує: Мандри','uk','ukraine_1991',NULL,NULL,NULL,'Текст записано на слух з аудіо. Аудіо (mp3): - http://us.share.geocities.com/ukrainbazar/Revolution/Ne_spy.mp3 - http://www.geocities.com/ukrainbazar/Revolution/Ne_spy.mp3 - http://www.domivka.net/tak_music.php - http://www.oblako.com/public/ne_spy.zip Підбір акордів: bohdanko','Вступ:  Dm C  (4)

Dm
Я тобі скажу,
де квітне дивний сад,
Dm
де срібляста ніч
тремтить у темних водах.
Dm
У далекий край
лежить нелегкий шлях,
доки хижа ніч кружля по колу.

Приспів 1:
Gm
Не спи, моя рідна земля!
Dm
Прокинься, моя Україно!
Відкрий свої очі у світлі далеких зірок!
Gm
Це дивляться з темних небес
Dm
загиблі поети й герої -
всі ті, що поклали життя за майбутнє твоє.

Програш:  Dm C  (4)

Тільки два шляхи...
Один веде у пекло.
Інший шлях веде
тебе туди, де світ.
Щоб знайти цей шлях,
послухай своє серце -
твоє серце знає,
як його знайти!

Приспів 1.

Програш:  Dm C  (4)

Я тобі повім
про мрію золоту,
що палким вогнем
горить в моєму серці.
Про щасливий край,
про радісних людей,
де життя кидає виклик смерти.

Приспів 1.

Приспів 2:
Не спи, моя рідна земля!
прокинься, моя Україно!
Відкрий свої очі у світлі далеких зірок.
Це дивляться з темних небес
загиблі поети й герої -
всі ті, хто так вірив у світле майбутнє твоє.

Програш:  Dm C  (2)

Не спи, моя рідна земля...  (2)

Фінал:  Dm','["pisni.org.ua", "cat:patriotic", "Патріотичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_815705'), datetime('now')),datetime('now'));
