INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_816611','Горіла Сосна і Явір','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'с. 415-416, два заспіви №846. Весільні пісні. У двох книгах. Книга 2 (Волинь, Поділля, Буковина, Прикарпаття, Закарпаття). Упор., примітки Шубравської М.М., нотний матеріал упорядкувала Бучель Н.А. - Українська народна творчість. Т. 17 (у двох книгах). Київ, Наукова Думка, 1982. 679с.','* Кожна стрічка співається двічі Сподобав мі ся здалека — натяк-звертання до Місяця? Пара — любощі: Весілля. Сосна-Вогонь-Вінок. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Три Гискри впало Три Морі стало. Десь узялася Молода Дівчина. Стала ж Вона сяяти. Горіла Сосна палала. Горіла Сосна і Явір Горiла Сосна палала Горіла Сосна Смерека Листки з приводу цієї Пісні: Пане Господаре на Твоїм Двору Ялина стоїть. Містична злука Вогню з Водою. Стежки до листків про Українські традиції.','Горіла Сосна і Явір
Сподобав мі ся Кавалір

Горіла Сосна й Смерека
Сподобав мі ся здалека

Горіла Сосна й палала
Під Нею Дівка стояла

Під Нею Дівка стояла
Русую Косу чесала

Ой Коси-коси ви мої
Вірно служили ви мені

Більше служить не будете
Під Білий Вельон підете

Під Білий Вельон під Фату
Більше я вас не заплету

Під Білий Вельон з Китицями
Більше не підеш Вулицями

Під Білий Вельон під Вінок
Більше не підеш у Танок

Під Білий Вельон під Стужку
Більше не підеш за Дружку

Під Білий Вельон під Стяжку
Тепер ти підеш за Свашку

Ой там у Лузі Качата
Будьте здорові Дівчата

Ой там у Лузі Горобці
Будьте здорові всі Хлопці    Аранжування медяне','["pisni.org.ua", "cat:dances", "cat:philosophic", "cat:vesilni", "cat:waltzes", "Пісні до танцю", "Філософські пісні", "Весільні пісні", "Вальси"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_816611'), datetime('now')),datetime('now'));
