INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_81603','Ой у полі криниченька','(Там стояла дівчинонька...). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'А вже весна скресла. Збірник гаївок. Львів, 2003.','* Кожна строфа повторюється двічі.','Ой у полі криниченька,
Там стояла дівчинонька.*

А там козак коня пасе,
Дівчинонька воду несе.

Козак єї переймає,
З відер воду виливає.

"Ой, козаче, козаченько,
Пусти мене додомоньку,

Бо я лиху матір маю —
Буде бити, добре знаю".

"Як тя мати буде бити,
Навчу я тя говорити:

Ой летіли гуси з броду,
Сколотили в ставі воду.

Док ся вода одстояла,
Я си трохи постояла.

А тепер я признаюся,
Що з козаком кохаюся.

Козак чорний, я білява,
Поберемся — буде пара.

Козак чорний, як той перець,
Я білява, як паперець."    Основна мелодія','["pisni.org.ua", "cat:vesnyanky-hayivky", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_81603'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_81603','Ой у полі криниченька','Ой у полі криниченька,
