INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8163603','Україно моя!','Музика: Віктор Пашник Слова: Олесь Бердник. Виконує: Віктор Пашник, Василь Литвин','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Україно моя, рідна мати моя,
Хто Ти є? Хто Ти є? -
Я питаю про те на весні солов''я,
Я запитую серце своє.
Хто Ти є? Хто Ти є? -
Я запитую серце своє.

Мені каже Дніпро: Україна - то Я!
А Карпати високі здаля:
Все шепоче у горах матуся твоя -
Невмируща вкраїнська земля!
Шепчуть гори здаля:
Невмируща вкраїнська земля!

Вірю, знаю: у горах матуся живе,
У Дніпровськім потоці співа,
Її серце - то небо весни грозове,
Її дума - печаль світова.
Її серце живе,
Її дума - печаль світова!

І зірки в далині - то Вкраїни вогні,
То все Ти! То все Ти!
Струни кобзи звенять, Україна в мені,
Ніби райдужні в небі мости!
То все Ти! То все Ти!
Ніби райдужні в небі мости!

Україно моя, рідна мати моя,
Хто Ти є? Хто Ти є? -
Я питаю про те на весні солов''я,
Я запитую серце своє.
Хто Ти є? Хто Ти є? -
Я запитую серце своє.','["pisni.org.ua", "cat:bardivski", "Бардівські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8163603'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8163603','Україно моя!','Україно моя, рідна мати моя,
