INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8167817','Зірочки яснії','Слова: Платон Воронько','uk','ukraine_before_1917',NULL,NULL,'http://www.malecha.org.ua/',NULL,'У широкому вікні
Є три зірочки ясні:
Перша - зірочка щаслива,
Друга - зірочка вродлива,
Третя - зірочка правдива,
Вірні подруги вони.

Люба донечко, засни
І тоді до тебе в сні
Всі три зірочки ясні
Прийдуть у таночку
В золотім віночку.

Щоб росла щаслива,
Щоб росла правдива
Донечка вродлива...','["pisni.org.ua", "cat:kolyskovi", "Колискові"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8167817'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8167817','Зірочки яснії','У широкому вікні
Є три зірочки ясні:
Перша - зірочка щаслива,
Друга - зірочка вродлива,
Третя - зірочка правдива,
Вірні подруги вони.

Люба донечко, засни
І тоді до тебе в сні
Всі три зірочки ясні
Прийдуть у таночку
В золотім віночку.

Щоб росла щаслива,
Щоб росла правдива
Донечка вродлива...');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8164205','Козак Нечай','Українська народна пісня. Виконує: Олексій Керекеша','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, з-за гори високої
З-під чорного гаю,
Ой, крикнули козаченьки:
Утікай, Нечаю!
Не журіться, не журіться,
Пани-отамани,
Поставив я охорону
Усіма шляхами.

Нечаю, Нечаю,          |
Тримай коня на припоні |
Для свого звичаю!      | (2)

Як я маю козак Нечай
Звідси утікати,
Славу мою козацькую
Марно потеряти?
То ж є в мене козак Шпак,
Ото добрий хлопець,
Він одразу дає знати,
Коли утікати.

Нечаю, Нечаю,          |
Тримай собі шабелечку  |
Для свого звичаю!      | (2)

Сідлай, хлопче,
Сідлай, малий, коня вороного,
Та побіжи в чисте поле,
Чи йде ляхів много?
Вертається малий хлопець,
Аж із Полоного:
Іде ляшків сорок тисяч
Тільки без одного.

Сідлай мені вороного,
Собі - буланого
Та й виріжем вражих ляхів,
Гей, що до одного!
Ой, не встиг козак Нечай
На коника спасти,
Враз ляхами, як снопами,
По два ряди класти.

Нечаю, Нечаю,          |
Тримай собі шабелечку  |
Для свого звичаю!      | (2)

Як розверне козак Нечай
Та ліве плече,
А вже ляхів - вражих синів
Та кров річкою тече!
Повернувся козак Нечай
На правую руку,
Ой, не вискочив Нечаїв кінь
Із ляшого руху.
Ой, як стисне козак Нечай
Коня острогами,
За ним ляхів сорок тисяч
З голими шаблями.
Пошпотався під Нечаєм
Коник на кубинку,
Зловив ляшок - скурвий синок
Його за чупринку.
Ой, вдарився козак Нечай
Об кулак рукою,
Ой, прийдеться розлучитись
З дітьми і жоною.
Гей, молоді козаченьки,
Котрий буде в місті,
Поклоніться матусеньці,
Нещасній невістці.

Нехай вона, нехай плаче,
А вже не виплаче,
Ой, над сином, над Нечаєм,
Чорний ворон кряче.
За час, за хвилинку,
За малу годинку
Качається Нечаєва
Голова на ринку.
Ой, не дбали вражі ляхи
На козацьку вроду,
Рвали тіло по кавалку,
Пускали на воду.

Нечаю, Нечаю...

Отак мужній козак Нечай
За Вкраїну бився,
І за те вічної слави
В внуках заручився!

Нечаю, Нечаю... Нечаю, Нечаю...
Нечаю, Нечаю... Нечаю...','["pisni.org.ua", "cat:istorychni", "cat:kozacki", "Історичні пісні", "Козацькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8164205'), datetime('now')),datetime('now'));
