INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8165409','Донечко моя, зіронько','Музика: Ігор Іванців, Галина Галига Слова: Аліна Шевчук, Галина Галига. Виконує: Ігор Іванців, Галина Галина','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ти - мрія моя, що здійснилася,
Ти - сонце душі моєї,
Зорею на світ народилася,
І дім осяваєш нею.
Картинко моя, намальована,  |
Ти - ніжність сама і ласка. |
Ти Богом мені подарована,   |
Твої оченята - казка!       | (2)

Приспів:
Донечко моя, зіронько,      |
Красуне моя, лебідонько,    |
Щастячко ясне, сонечко,     |
Люблю тебе, мила донечко!   | (2)

Без тебе не бачу майбутнього,
В тобі мої дні і ночі,
Від першого дня незабутнього
Молитву в душі шепочу.
Трояндо моя зачарована,     |
Надію в тобі лелію,         |
Ти цвітом життя обдарована, |
Для тебе живу і мрію!       | (2)

Приспів.

Донечко моя, зіронько...
Щастячко ясне, сонечко...

Приспів','["pisni.org.ua", "cat:pro-ditey", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8165409'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8165409','Донечко моя, зіронько','Ти - мрія моя, що здійснилася,
