INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8169307','Василько','Музика: Василь Дунець Слова: Василь Дунець. Виконує: Василь Дунець','uk','ukraine_1991',NULL,NULL,'www.vkontakte.ru',NULL,'Оченята - вуглики карапуза внучка
Пильно придивляються до мойого вушка.
Делікатним пальчикам підійшла знахідка
І вп''ялися нігтики, щоб вона не втікла.

Приспів:
Василечку, Васильку, чорнооке диво,
Все тобі цікаве і таке звабливе.
Що ухопиш в ручки, зразу тягнеш в ротик,
Нігтики гостренькі - драпаєш, мов котик.

Мало не кричу: "Болить!", а йому байдуже,
Ще й сміється і пищить, любить вуха дуже.
А як вхопить в кулачок часом жмут волосся,
Думаєш: "В кого ж таке, вредненьке вдалося?"

Приспів.

Підростає внучок мій, з кожним днем щось нове,
Ось, в колисці він встає сам, без допомоги!
А сьогодні я прийшов і його шукаю,
Бо він вже на чотирьох по хаті гасає!

Приспів.

Ти для нас, онучку, радість і забава,
Як ми всі чекали, коли скажеш: "Мама!"
Я із нетерпінням теж тепер чекаю,
Коли скажеш: "Діду, давай заспіваєм!"
Ну давай!','["pisni.org.ua", "cat:pro-ditey", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8169307'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8169307','Василько','Оченята - вуглики карапуза внучка
Пильно придивляються до мойого вушка.
Делікатним пальчикам підійшла знахідка
І вп''ялися нігтики, щоб вона не втікла.

Приспів:
Василечку, Васильку, чорнооке диво,
Все тобі цікаве і таке звабливе.
Що ухопиш в ручки, зразу тягнеш в ротик,
Нігтики гостренькі - драпаєш, мов котик.

Мало не кричу: "Болить!", а йому байдуже,
Ще й сміється і пищить, любить вуха дуже.
А як вхопить в кулачок часом жмут волосся,
Думаєш: "В кого ж таке, вредненьке вдалося?"

Приспів.

Підростає внучок мій, з кожним днем щось нове,
Ось, в колисці він встає сам, без допомоги!
А сьогодні я прийшов і його шукаю,
Бо він вже на чотирьох по хаті гасає!

Приспів.

Ти для нас, онучку, радість і забава,
Як ми всі чекали, коли скажеш: "Мама!"
Я із нетерпінням теж тепер чекаю,
Коли скажеш: "Діду, давай заспіваєм!"
Ну давай!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8169450','Ворозочки з ожиночки, колиска з горіха','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Книга: Дитячий фольклор,Київ,"Дніпро"1986','Ворозочки - мотузки, на яких підвішувалася колиска. Скорнєти - збудити.','Ворозочки з ожиночки, колиска з горіха,
Колише сі у колисці мамина потіха.
Коби тебе, дитиночко, нічо не боліло -
Ані ручки, ані ніжки, ні біленьке тіло.
Ой летіла зозулечка через садовину
Та впустила сиве перце, скорнєла дитину.
Бодай з тебе, зозулечко, все пір''я упало:
Скорнєла-с ми дитиночку, ще би було спало.','["pisni.org.ua", "cat:kolyskovi", "Колискові"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8169450'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8169450','Ворозочки з ожиночки, колиска з горіха','Ворозочки з ожиночки, колиска з горіха,
Колише сі у колисці мамина потіха.
Коби тебе, дитиночко, нічо не боліло -
