Бодай з тебе, зозулечко, все пір''я упало:
Скорнєла-с ми дитиночку, ще би було спало.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8168575','Ой ну, люлі, дитя, спать','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Книга: Дитячий фольклор,Київ,"Дніпро"1986',NULL,'Ой ну, люлі, дитя, спать!
Пішла мати жито жать
Та й вижала три квітки:
Що первую сонливу,
А другую дрімливу,
А третюю щасливу.
Ой щоб воно спало,
Щастя-долю мало
І добру годину
На малу дитину.
Ой щоб воно спало
І спати хотіло,
Як квіт, червоніло.','["pisni.org.ua", "cat:dytyachi", "cat:kolyskovi", "Дитячі пісні", "Колискові"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8168575'), datetime('now')),datetime('now'));
