INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8170676','Христе, стрінутись з тобою','Слова: о. Й. Кишакевич','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Христе, стрінутись з Тобою,
Одне бажання моє
З серця і душі цілої,
Що для Тебе лиш жиє.
Тебе серцем всім обняти |
І прийняти до душі      |
Свята тайно не понята - |
Це на думці все мені.   | (2)

