INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8170950','Вже морок щез','Музика: о. С. Воробкевич Слова: о. В. Б. Мендрунь','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Приспів:
Христос воскрес!
Христос воскрес із мертвих!
Христос воскрес!
Христос воскрес із мертвих!
Смертю смерть подолав,
Смертю смерть подолав,
І тим, що в гробах життя дарував!
Життя, життя, життя дарував!
Життя, життя, життя дарував!
Життя дарував!

Вже морок щез
Із душ, тілес —
Христос воскрес!
У дзвоні Служб,
У дзвоні Мес —
Христос воскрес!

Приспів.

В вінку чудес
Життя з небес —
Христос воскрес!
Вже морок щез:
Сіяє хрест —
Христос воскрес!

Приспів.','["pisni.org.ua", "cat:cerkovni", "cat:christian", "cat:voskresni", "Церковні пісні", "Пісні на християнську тематику", "Воскресні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8170950'), datetime('now')),datetime('now'));
