Приспів.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8170979','Днесь весело',NULL,'uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Днесь весело дзвони дзвонять,
Днесь, бо торжество торжеств,
Бо наш Господь і Спаситель
Славно з гробу встав, воскрес!

Сила гробної печаті
Показалась за слаба,
Щоб могти затримать тіло
Пана смерті і життя.

Отже, тішмось, веселімся,
Заспіваймо грімко днесь:
Честь і слава Богу Сину,
Що із мертвих встав, воскрес!','["pisni.org.ua", "cat:voskresni", "Воскресні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8170979'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8170979','Днесь весело','Днесь весело дзвони дзвонять,
