INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8169013','Зажурилась Україна','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1960','http://www.a-pesni.golosa.info/kazaki/kuban/zazukr.htm','Записана летом 1960 в ст. Староминской от Марии Архиповны Сипач. Одной из причин немилости Екатерины II к запорожцам были жалобы польского короля Потоцкого на беспокойных соседей, запорожских казаков. В песне выражен гнев запорожцев к Потоцкому, упреки Екатерине II. Варианты: А. Бигдай, вып. 2, стр. 110, № 65. См. песни про пана Потоцкого в сб. Г. Нудьга. Писни та романсы украинських поэтив. К., 1965, т. 1, стр. 146, 148. И. Ф. Варавва. Песни казаков Кубани. Краснодар, 1966, № 215.','Зажурилась Україна
Як мала дитина.
Ніхто її не шанує,
Козачество гине.

Ой ти, графе, пан Потоцький,
Распроклятий сину.
Занапастив Литву й Польщу,
Хочеш - й Україну.

Така думка твоя була,
Щоб королем стати,
А ти пішов до цариці
Помочі прохати.

Вража мати Катерина
Негаразд вчинила:
Степ широкий, край веселий
Та й занапастила.

А де були очерети,
Тепер попахали.
А де були батьки наші -
Вороги забрали.','["pisni.org.ua", "cat:istorychni", "Історичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8169013'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8169013','Зажурилась Україна','Зажурилась Україна
Як мала дитина.
Ніхто її не шанує,
Козачество гине.

Ой ти, графе, пан Потоцький,
Распроклятий сину.
Занапастив Литву й Польщу,
Хочеш - й Україну.

Така думка твоя була,
Щоб королем стати,
А ти пішов до цариці
Помочі прохати.

Вража мати Катерина
Негаразд вчинила:
Степ широкий, край веселий
Та й занапастила.

А де були очерети,
