А де були батьки наші -
Вороги забрали.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8171409','Приготуйся, вишній троне',NULL,'uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Приготуйся, вишній троне,
Світом сумно вдарте, дзвони:
Вже йде Діва Богомати
В небі вічно царствувати
У Сіоні в зір короні
Разом з Сином своїм єдиним.
Празник вітайте,
Пісні співайте на честь Марії!

О, Маріє, світу Мати,
Йдеш одіта в світлі шати,
І радіють неба хори,
Срібних ангелів собори,
Йдуть рядами із піснями
Тебе вітати, Господня Мати,
Господню звану, так довго ждану
Всіми святими.

В небі слава, радість, втіха -
На землі туга велика:
Апостоли гірко плачуть,
Вже Пречистої не бачать.
Серця в''януть, сльози кануть,
Бо їх надія, Діва Марія,
Квітка лелія, з тілом-душею
В небо злинула.

Не сумуйте, вірні діти,
Вже вам лиха не терпіти,
Ваше серце не змарніє,
Бо над вами все Марія,
Божа Мати благодати
Про усіх дбає, охороняє,
Помочі-ласки в Сина благає,
На вічні віки!','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8171409'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8171409','Приготуйся, вишній троне','Приготуйся, вишній троне,
Світом сумно вдарте, дзвони:
Вже йде Діва Богомати
