INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8170373','Єдиним серцем і устами','Слова: о. Іван Дуцько','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Єдиним серцем і устами
Хвалити Господа зачнім.
Честь Богу даймо молитвами, |
Смиренно духа приклонім.    | (2)

Молитва щира, Богу мила,
Хай до небес аж вознесесь,
Як благовонний дим кадила    |
За Церков всю і нарід весь.  | (2)

Владико, Господи Небесний,
Помилуй нас і пом''яни,
Прийми молитви дар словесний, |
