комп''ютерне відтворення (128 kbps). Варіант 1','["pisni.org.ua", "cat:cerkovni", "Церковні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8170373'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8170373','Єдиним серцем і устами','Єдиним серцем і устами
Хвалити Господа зачнім.
Честь Богу даймо молитвами, |
Смиренно духа приклонім.    | (2)

Молитва щира, Богу мила,
Хай до небес аж вознесесь,
Як благовонний дим кадила    |
За Церков всю і нарід весь.  | (2)

Владико, Господи Небесний,
Помилуй нас і пом''яни,
Прийми молитви дар словесний, |
Від нужди й скорбі нас храни. | (2)

Тобі готові ми служити,
Весь вік синівської любви,
З цілого серця Тя просити,    |
Ти з неба нас благослови.     | (2)

І благодать святу зсилай нам,
