INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8172756','Золоте весілля','(Бабушка рядышком с дедушкой...). Музика: Раймонд Паулс Слова: Ілля Резнік. Виконує: Діана Глухова','uk','ukraine_1991',NULL,NULL,'http://www.ledi-di.ucoz.ua',NULL,'До бабусі і до дідуся
Зібралась у дім родина вся,
І сьогодні "Гірко!" їм кричать
Сорок правнуків і двадцять п''ять внучат.

Приспів:
Наші бабуся із дідусем,
Просимо вас поруч сісти.
Наші бабуся із дідусем -
Перші в оркестрі солісти.
Наші бабуся із дідусем -
Пара на радість багата.
Наші бабуся із дідусем,
Знов, як колись - молодята.

В пару цю закохані усі:
Дітлахи, матусі, татусі.
У бабусі є співацький хист,
А дідусь у нас - завзятий танцюрист.

Приспів.

У святковий у весільний день
Їм бажаєм щастя і пісень,
Тож піднімем кухлі у руках,
Вип''ємо за них парного молока!','["pisni.org.ua", "cat:dytyachi", "Дитячі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8172756'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8172756','Золоте весілля','До бабусі і до дідуся
Зібралась у дім родина вся,
І сьогодні "Гірко!" їм кричать
Сорок правнуків і двадцять п''ять внучат.

Приспів:
