INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8172450','Заграйте, дзвони','Слова: о. Й. Кишакевич','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Заграйте, дзвони, з Петра святині,
Най звук їх вчує земля ціла,
Свято велике і празник нині             |
Двох апостолів Петра і Павла!           | (2)

Заграйте, дзвони, розбийте в порох
Звуком могучим ложні слова,
Хай світ весь знає, хай вчує ворог,     |
Що не хитнеться скала Петра.            | (2)

Заграйте, дзвони, звуком чудовим,
У наших серцях віру скріпіть,
При тобі, сильна скало Петрова,         |
Весь український нарід стоїть.          | (2)

Буде стояти і не хитнеться,
Як та могуча Петра скала,
Хоч смерть понести нам всім прийдеться, |
Смерть на подобу Петра і Павла.         | (2)','["pisni.org.ua", "cat:cerkovni", "Церковні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8172450'), datetime('now')),datetime('now'));
