INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8171116','Понад сонце','Слова: о. І. Дуцько','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Понад сонце, понад зорі,
Понад обрії просторі
Господь свій престіл ставляє,
Царство вишнє обіймає.

Приспів:
Земле, з небом примирися,
Спасу своєму вклонися,
Земле, з небом примирися,
Спасу своєму вклонися,
Богу небесному!

Праворуч Бог Син сідає,
Бог Отець Його вінчає,
Ангели царя вітають,
Йому славу й честь співають.

Приспів.

Веселись, горо Оливна,
Ти між горами предивна —
Ти Сіон, Тавор займаєш,
Славу Спаса оглядаєш.

Приспів.

Янгол людям вість голосить,
Бог Спаситель люд підносить —
Місце в небі всім зробити,
Звідки зійде світ судити.

Приспів.

О, Ісусе, Тебе просим,
Наші серця в небо зносим:
Не кидай нас сиротами,
Будь благим Отцем над нами.

Приспів.','["pisni.org.ua", "cat:cerkovni", "cat:christ", "Церковні пісні", "Пісні до Ісуса Христа"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8171116'), datetime('now')),datetime('now'));
