INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8171272','В Назареті зацвіла лелія','Слова: о. І. Дуцько','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'В Назареті зацвіла лелія,
То на світ родилася Марія,
Діва прекрасна, як зоря ясна, |
Як ся з''явила, всіх звеселила |
На землі!                     | (2)

Веселися, Йоакиме, нині
І ти, Анно, щось мати дитині!
Старушка Анна неплодна звана  |
Доню цілує, щастя в Ній чує   |
Між людьми.                   | (2)

Діти Єви вітають Марію,
Бо вже бачать спасения надію:
Родилась чиста Діва Невіста,  |
Святе дитятко, як ангелятко   |
Із небес.                     | (2)

Незчисленні ангели ликують
І блаженні святі торжествують,
Вже оглядають і величають     |
Земну дівицю, неба Царицю     |
Марію.                        | (2)

Знає добре Бог Отець із неба,
Як спасення зіслати нам треба,
3 світа цілого для Сина свого |
Матір шукає і вибирає         |
Марію.                        | (2)

О Маріє преблагословенна,
В Назареті для нас народженна,
Ми Тя вітаєм, просим, благаєм |
Радосте многа, молись до Бога |
За нами.                      | (2)','["pisni.org.ua", "cat:cerkovni", "cat:do-bohorodyci", "Церковні пісні", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8171272'), datetime('now')),datetime('now'));
