INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8173817','Школо моя','Музика: Євген Пухлянко Слова: Володимир Матвієнко. Виконує: Григорій Гребініченко','uk','ukraine_1991',NULL,NULL,'інтернет',NULL,'Школо моя!
Я ніколи тебе не забуду.
Школо моя!
Ти - домівка в дитинстві була.
Школо моя!
Ти не знаєш, як всі тебе люблять.
Школо моя!
Мов за руку, в життя повела.

Приспів:
Мов сонце, світи, моя школо!
Дитинства мого дивний край.
Тебе не забуду ніколи
І ти мене не забувай!

Школо моя!
Ти є перша свята Альма-матер,
Рідна моя,
Ти - надійний в житті оберіг.
В серці навік
Та любов до людей, що дала ти,
Совість і честь,
І початок з прийдешніх доріг.

Приспів. (2)','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8173817'), datetime('now')),datetime('now'));
