INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8172312','Царице благодати','Слова: о. В. Б. Мендрунь','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'О, Царице, о, Царице
Благодати, благодати,
О, Царице благодати,
Непорочна Діво Мати,
Жаждущим даруєш Ти
Спасителя - Визволителя.

Приспів:
О, Маріє, просим щиро:
Дай народам сонце миру.
О, Маріє, просим щиро:
Дай народам сонце миру.
Визволи, визволи від усяких бід!

Володарко, володарко,
Ти — хмарина,
Ти — хмарина,
Володарко, Ти — хмарина,
Що зросила ласки Сина,
Не минай наш рідний край,
Схили лице, Богородице.

Приспів.

Як Месія, як Месія,
Нам явився, нам явився,
Як Месія нам явився —
Світ Марії поклонився:
Мати-зіронька зійшла
У простоті, завжди в Господі.

Приспів.','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8172312'), datetime('now')),datetime('now'));
