INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8174116','Нині радість нам усім','Українська народна пісня. Виконує: Остап Нижанківський','uk','ukraine_before_1917',NULL,NULL,'Антологія лемківської пісні, Львів, "Афіша", 2005, с.31',NULL,'Нині радість нам усім,
Хвалу Богу принесім!
Господь Бог великий
Вродивсь чоловіком
З Діви Марії.

Ангел мовив пастирям,
Що Христос родився нам;
Йдіть Його вітати,
Бога величати
Народженого.

Ми на Нього чекали,
З тугою виглядали,
І Він народився,
В яслах положився
У Вифлеємі.

Зіронька присвічує,
До Христа шлях вказує.
Царі дари дали,
В яслах привітали
Ісуса Дитя.

Сьогодні веселімся,
Христові поклонімся.
Просім, щоб у славі
Ми з Ним пребували
В небі й на землі!','["pisni.org.ua", "cat:lemkivski", "Лемківські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8174116'), datetime('now')),datetime('now'));
