INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_817518','Бандуристе, Орле Сизий','(Н. Маркевичу). Музика: народна Слова: Тарас Шевченко. Виконує: Ансамбль Львівського Університету "Черемош", Ірина Білик, Бандурна Розмова, Олексій Керекеша','uk','ukraine_before_1917',NULL,'1840','1. Поетика - http://poetry.uazone.net/kobzar/n_markevychu.html 2. Плавай, плавай, лебедонько. - К.: Музична Україна, 1989. - С. 56. 3. http://www.ukrainianmusic.net/catalog/product_info.php/products_id/601/language/uk 4. Piosenki lemkowskie i ukrainskie. - Warzhawa: Akademicki klub turystyczny "Maluch", 2001.','Там Синєє Море виграває хвалить Бога — порівняти зі Святоріздвяними піснями-звичаями про Різдво Світа та містичну Купіль Бога. Спасительна: світ не по Правді. Українські релігійні роздуми про Воскресіння, Неволю і Спасіння. Нема в світі Правди не зіскати. Та ба Доля приборкала меж людьми чужими. Листки з приводу цієї Пісні: Українські реліґійні роздуми про Неволю та Спасіння Коляда і Великдень: Різдво і Відродження Світа. Стежки до листків про Українські традиції. * Акорди подані за джерелом 4 у тональності Dm, що відповідає доданим файлам (у джерелі 4 тональність Am). Варіант акордів [3] підібрано на слух за аудіо-джерелом 3 у тональності Gm (підібрав: "bohdanko"). **Оригінальний текст поезії Тараса Шевченка. С.-Петербург, 9 мая 1840 року. Микола Андрійович Маркевич:...М.А. Маркевич був добре знайомий з Тарасом Шевченком. З ним він підтримував теплі дружні стосунки на протязі всього життя. Шевченко часто зустрічався з Маркевичем і в Петербурзі, і під час поїздок в Україну. Тарас Григорович звертався за порадами до історика під час написання "Гайдамаків", а також у зв''язку з роботою над офортами на історичну тематику. Саме йому він присвятив свого чудового вірша "Бандуристе, орле сизий", покладеного згодом на музику.... У джерелі 2 посилання на першоджерело: Народні пісні на слова Тараса Шевченка. - К. 1961. У джерелі 3 можна прослухати фрагмент виконання пісні бандуристами Тарасом Лазуркевичем та Олегом Созанським.','Бандуристе, орле сизий!
Добре тобі, брате:
Маєш крила, маєш силу,   |
Є коли літати.           |(2)

Тепер летиш в Україну —
Тебе виглядають.
Полетів би за тобою,     |
Та хто привітає.         |(2)

Там повіє буйнесенький,
Як брат, заговорить;
Там в широкім полі воля; |
Там синєє море!          |(2)

Полетів би, послухав би,
Заплакав би з ними...
Та ба, доля приборкала   |
Меж людьми чужими.       |(2)
Акорди:*
Бандуристе, орле сизий!
Добре тобі, брате:
Маєш крила, маєш силу,
Є коли літати,
Маєш крила, маєш силу,
Є коли літати.
Акорди [3]:
Бандуристе, орле си_ зий!
Добре тобі, бра_ те:
Маєш крила, маєш силу,
Є коли літати,
Маєш крила, маєш си_ лу,
Є ко_ ли літати.

Бандуристе, орле сизий!
Добре тобі, брате:
Маєш крила, маєш силу,
Є коли літати.
Тепер летиш в Україну —
Тебе виглядають.
Полетів би за тобою,
Та хто привітає.
Я й тут чужий, одинокий,
І на Україні
Я сирота, мій голубе,
Як і на чужині.
Чого ж серце б''ється, рветься?
Я там одинокий.
Одинокий... а Украйна!
А степи широкі!
Там повіє буйнесенький,
Як брат, заговорить;
Там в широкім полі воля;
Там синєє море
Виграває, хвалить бога,
Тугу розганяє;
Там могили з буйним вітром
В степу розмовляють,
Розмовляють сумуючи,
Отака їх мова:
"Було колись — минулося,
Не вернеться знову".
Полетів би, послухав би,
Заплакав би з ними...
Та ба, доля приборкала
Меж людьми чужими.**','["pisni.org.ua", "cat:emigration", "cat:nostalgia", "cat:patriotic", "Пісні про еміґрацію", "Пісні з ностальгічними мотивами", "Патріотичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_817518'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_817518','Бандуристе, Орле Сизий','Бандуристе, орле сизий!
