INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8176358','Батярська любов','Музика: Віктор Морозов Слова: Андрій Панчишин. Виконує: Віктор Морозов','uk','ukraine_1991',NULL,NULL,'http://www.mo-productions.com/',NULL,'якось рано-вранці
десь на Погулянці
на траві зеленій була ше роса
вийшов гонорово
батяр з Личакова
на натуру рідну вигуляти пса

фацет кури
пес літає
шо зобачи - підливає

раптом на паґурку
види хлоп фіґурку
файна як та ружа панночка іде
ше й веде на смичку
сучку невеличку
зара було видко - шось таки буде

заки пес обнюхав сучку
батяр панну брав за ручку

з того ніц доброго не буде
бо повідают старші люди
шо страшна батярска любов
буде нагла лятися кров

заки говорили
пси си полюбили
і не раз а може навіть і не два
панна як то вздріла
голову згубила
по страченій цноті плакала трава

батяр був порядний дуже
купив вельон своїй ружі

дві обручки купив
двайці дека влупив
кавалєрску волю тихо пом''янув
як ішли до шлюбу
стріли Франю грубу
батяр лівим оком хтиво їй мруґнув

Франя си не відвернула
і на батяра мруґнула

з того ніц доброго не буде
бо повідают старші люди
шо страшна батярска любов
буде нагла лятися кров

панна з-під корсета
витягла штилєта
вдарила го в груди а затим себе
коло церкви впали
моцно си обняли
не буде з батяром щастя
не буде

їх ховали в їднім гробі
а Личаків був в жалобі

песики тужили
довго не прожили
їхня песька доля була дуже злов
на могилі сіли
тай закам''яніли
бо собача вірність більша ніж любов

аньолок мурмурови
а коло него пси
нема на Личакови
страшнішої краси

з того ніц доброго не буде
бо повідают старші люди
шо страшна батярска любов
буде нагла лятися кров','["pisni.org.ua", "cat:bardivski", "Бардівські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8176358'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8176358','Батярська любов','якось рано-вранці
десь на Погулянці
на траві зеленій була ше роса
вийшов гонорово
батяр з Личакова
на натуру рідну вигуляти пса

фацет кури
пес літає
шо зобачи - підливає

раптом на паґурку
види хлоп фіґурку
файна як та ружа панночка іде
ше й веде на смичку
сучку невеличку
зара було видко - шось таки буде

заки пес обнюхав сучку
батяр панну брав за ручку

з того ніц доброго не буде
бо повідают старші люди
шо страшна батярска любов
буде нагла лятися кров

заки говорили
пси си полюбили
і не раз а може навіть і не два
панна як то вздріла
голову згубила
по страченій цноті плакала трава

батяр був порядний дуже
купив вельон своїй ружі

дві обручки купив
двайці дека влупив
кавалєрску волю тихо пом''янув
як ішли до шлюбу
стріли Франю грубу
батяр лівим оком хтиво їй мруґнув

Франя си не відвернула
і на батяра мруґнула

з того ніц доброго не буде
бо повідают старші люди
шо страшна батярска любов
буде нагла лятися кров

панна з-під корсета
витягла штилєта
вдарила го в груди а затим себе
коло церкви впали
моцно си обняли
не буде з батяром щастя
не буде

їх ховали в їднім гробі
а Личаків був в жалобі

песики тужили
довго не прожили
їхня песька доля була дуже злов
на могилі сіли
тай закам''яніли
бо собача вірність більша ніж любов

аньолок мурмурови
а коло него пси
нема на Личакови
страшнішої краси

з того ніц доброго не буде
бо повідают старші люди
шо страшна батярска любов
буде нагла лятися кров');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8175777','Як я був малим хлопцем','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Як я був малим хлопцем,
Не знав я, що то любов.
Не знав я, що то кохатись
З дівчинов молодов.

Почав я підростати,
Став з мене молодець.
Почав я пари шукати,
Як сивий голубець.

До першої ходив я,
А другу я любив.
А третю чорнобриву
До серденька тулив.

Четверта мя любила,
А п''ята кохала.
А шоста за мнов тужила
І гірко плакала.

До сьомої - звечора,
До восьмої - впівніч.
Дев''яту цілував я,
Десятій: "Добраніч".

З одинадцятов голубков
Я на спацер піду.
Дванадцяту миленьку
До шлюбу поведу.

Ой Боже, ти мій Боже,
І що ж я наробив?
Чому я першій дівчині
Присягу не зложив?    Фонограма-мінус (mp3, 128 kbps). весільний вальс','["pisni.org.ua", "cat:dances", "cat:waltzes", "Пісні до танцю", "Вальси"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8175777'), datetime('now')),datetime('now'));
