INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_817676','Ти такий як я, в тебе жовті сльози (Небо*)','Музика: Ірена Карпа Слова: Ірена Карпа. Виконує: Ірена Карпа, Фактично самі','uk','ukraine_1991',NULL,NULL,'слова розібрано на слух: LO-FI Травми, співає Ірена Карпа','Ірена Карпа, Фактично Самі: LO-FI Травми, Mp3 — http://www.karpa.name/en/songs.html Видиво — http://www.karpa.name/ua/video.html','Ти такий як я, в тебе жовті сльози,
В тебе коси до землі.
У твоє гілля заплелись морози.
Відпусти їх, ще ж малі.

Я ногами тут, а лицем на південь,
Подивись, подивись.
Там на тебе ждуть, там твоя царівна,
Бережись її, бережись.

Приспів:
Але надвоє небо не поділить,
Бути з тобою до смерті або на волі жить.

Ти такий як я, відчинились двері,
Звідти вийшло сім вітрів.
Рознесуть тебе геть по всій пустелі,
Хто до тебе був той згорів.

З твого тіла вже колоситься жито,
Але море без води.
Я зберу тебе, будеш знову жити
Як завжди, бо так завжди.

Приспів.','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_817676'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_817676','Ти такий як я, в тебе жовті сльози (Небо*)','Ти такий як я, в тебе жовті сльози,
