INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8176373','Кнайпа зацофана','Музика: Віктор Морозов Слова: Андрій Панчишин. Виконує: Віктор Морозов','uk','ukraine_1991',NULL,NULL,'http://www.mo-productions.com/',NULL,'Є на Личакови кнайпа зацофана
Ту ніхто не видів ні їдного пана
Правдивого пана
Жеби був в краваті
Самі гопштаплєри в курточках на ваті

Матка Боска!
Шо то буде?
Ойсь-таріді-ріді-да
Влодко Стефка вальнув в груди
Ойсь-таріді-ріді-да
Стефко Влодка в яя копа
Як цизорик склало хлопа
Шкло си било
Скрипка грала
На паркєти крев си ляла
Ойсь-таріді-ріді-ріді-дана
Хтось не дожиє до рана

На столах дубових обруси непрані
Ту ніхто не видів правдивої пані
Жеби в капелюшку
А на нему квітки
Ту самі лахудри наставляют литки

Ой мамуню!
Шо то буде?
Ойсь-таріді-ріді-да
Пиво виляла на груди
Ойсь-таріді-ріді-да
Через пупец на коліна
Дзюркотіла зимна піна
Шкло си било
Скрипка грала
На паркєти крев си ляла
Ойсь-таріді-ріді-ріді-дана
Хтось не дожиє до рана

А в тій кнайпі Мошко на скрипочци грає
