INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8175756','Мала баба курку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Мала баба курку.
Курка ся не несла.
Взяла баба чубатеньку
На базар понесла.

Злетів яструб з неба
Забрав курку в баби.
Баба кричить репетує:
"Віддай курку, драбе!"

Кричить баба, кличе
"Чоловіче Юрку,
Поможи ми відібрати
Чубатеньку курку!"

Летить Юрко, летить,
Нічого не баче -
Тільки чує десь далеко
Курка кухкудаче.

Нащо було курку
На базар возити?
Краще було чубатеньку
В борщику зварити.    Фонограма-мінус (mp3, 128 kbps). весільна полька','["pisni.org.ua", "cat:dances", "cat:polky", "Пісні до танцю", "Польки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8175756'), datetime('now')),datetime('now'));
