INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8176052','Беру лен, беру лен','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Антологія лемківської пісні, Львів, "Афіша", 2005, с.271','Виконує: Осип Ференц, с.Висова','1. Беру лен, беру лен, борозду за тижден.
Вибралам до краю, воз мене, шугаю!

2. Беру лен, беру лен, сама команичка,
Воз мене, шугаю, хоц я невеличка.

3. Хоц  я невеличка, але я шумничка,
Стану коло бочка, яко фраїрочка.

4. Ой лене, мій лене, мій зелений лене,
Хто тя ту посіяв, най ті і вибере.

5. Посіяли його миленького ручки,
Я го буду брати стиха, помалючки.

6. Беру лен, беру лен, зимна роса на нім,
Пішов мій миленький, і я піду за ним','["pisni.org.ua", "cat:lemkivski", "Лемківські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8176052'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8176052','Беру лен, беру лен','1. Беру лен, беру лен, борозду за тижден.
