INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8181171','Хмарка-хмаринонька',NULL,'uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Хмарка-хмаринонька, хвилька-хвилинонька,
Леле, дитинонько спи, засинай,
Леле, дитинонько спи, засинай.

Сонечко втомиться, в море закотиться,
