INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8176070','А тоді, а тоді веселенька била','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Антологія лемківської пісні, Львів, "Афіша", 2005, с.290','Виконує: Антоніна Прибило','1. А тоді, а тоді веселенька била,
Як мя моя мамця на ручках носила. (2)

2. Юж єм ся оженив, юж буду жену мав,
Юж я вас, дівчата, не буду любував. (2)

3. Дівчата, дівчата, любуйтеся самі,
Ой, бо наші хлопці любляться з жінками... (2)

4. Фраїр мій, фраїр мій, а я його жена,
А я його жена, як ружа червена. (2)

5. Фраїр мій, фраїр мій, я тобі не вірю,
Же мя будеш любив, як ся зостарію. (2)

6. Дівчатко, дівчатко, можеш мі вірити,
Же я тя не буду на старість любити. (2)','["pisni.org.ua", "cat:lemkivski", "Лемківські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8176070'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8176070','А тоді, а тоді веселенька била','1. А тоді, а тоді веселенька била,
