INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8177705','Мова у серці народу','Музика: Надія Красоткіна Слова: Надія Красоткіна. Виконує: Надія Красоткіна','uk','ukraine_1991',NULL,NULL,'http://krasotkina.com',NULL,'Наче юна зоря світанкова,
Ти лісами, степами ідеш,
Українська чарівная мово,
Ти у серці народу живеш!

Мелодійна моя, промениста,
Як Земля, твій багатий словник.
Українськая мово пречиста,
Ти ж у серці народу навік!

І, як промені сонця, чудова,
Ти у світі ніколи не вмреш,
Українська чарівная мово,
Ти у серці народу живеш!

Як із моря не висушить воду,
Не злічити джерел і струмків,
Рідна мова у серці народу
Буде жити навіки-віків!

Українська прабатьківська мово,
До зірок через терни ідеш.
Рідна мово моя пелюсткова,
Ти у серці народу живеш!','["pisni.org.ua", "cat:pisni-pro-movy", "Пісні про рідну мову"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8177705'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8177705','Мова у серці народу','Наче юна зоря світанкова,
