INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8184307','Кроковеє колесо','Музика: Людмила Іваннікова Слова: народні','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256 с.',NULL,'Кроковеє колесо, колесо
Вище тину стояло, стояло.
Много дива видало, видало.
Чи бачило колесо, колесо,
Куди нелюб поїхав, поїхав?
За ним трава полягла, полягла,
І діброва загула, загула.

Кроковеє колесо, колесо
Вище тину стояло, стояло.
Много дива видало, видало.
Чи бачило колесо, колесо,
Куди милий поїхав, поїхав?
За ним трава зелена, зелена,
І діброва весела, весела!','["pisni.org.ua", "cat:vesnyanky-hayivky", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8184307'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8184307','Кроковеє колесо','Кроковеє колесо, колесо
Вище тину стояло, стояло.
Много дива видало, видало.
Чи бачило колесо, колесо,
Куди нелюб поїхав, поїхав?
За ним трава полягла, полягла,
І діброва загула, загула.

Кроковеє колесо, колесо
Вище тину стояло, стояло.
Много дива видало, видало.
Чи бачило колесо, колесо,
Куди милий поїхав, поїхав?
За ним трава зелена, зелена,
І діброва весела, весела!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_818272','Веснянка-забавлянка','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Весняночка, паняночка,
Хто по тобі ходить,
Ой, там козак дівчиноньку,
За рученьку водить.

Ой, на нашій, на веснянці,
Чистенько-біленько,
Ой, ніхто так не заграє,
Як наш коваленко.

Коваленко, грає-грає,
А парубок в танці,
Як не візьме ту дівчину,
То піде у танці.

Закопали горщик каші,
Ще й рака живого,
Щоб на нашій, на веснянці
Не було нікого.

Закопали горщик каші,
Ще й живого півня,
Щоб на нашій,  на веснянці,
Збиралася збірна.','["pisni.org.ua", "cat:vesnyanky-hayivky", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_818272'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_818272','Веснянка-забавлянка','Весняночка, паняночка,
Хто по тобі ходить,
Ой, там козак дівчиноньку,
За рученьку водить.

Ой, на нашій, на веснянці,
Чистенько-біленько,
Ой, ніхто так не заграє,
Як наш коваленко.

Коваленко, грає-грає,
А парубок в танці,
Як не візьме ту дівчину,
То піде у танці.

Закопали горщик каші,
Ще й рака живого,
Щоб на нашій, на веснянці
Не було нікого.

Закопали горщик каші,
Ще й живого півня,
Щоб на нашій,  на веснянці,
Збиралася збірна.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8184450','Іванчику-білоданчику','Музика: Леопольд Ященко Слова: народні','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256 с.',NULL,'Іванчику-білоданчику,
Поплинь, поплинь по Дунайчику,
Поплинь, поплинь по Дунайчику
Та візьми гребінчика,
Розчеши русу косу
Ще й чорненькі брівця.

Іванчику-білоданчику,
Поплинь, поплинь по Дунайчику,
Поплинь, поплинь по Дунайчику.
Та й візьмися попід бочки.
Покажи нам свої скочки,
Та візьми гребінчика.
Розчеши русу косу
Ще й чорненькі брівця.

Іванчику-білоданчику,
Поплинь, поплинь по Дунайчику,
Поплинь, поплинь по Дунайчику.
Та вмий собі біле личенько.
Протри собі карі оченька, гей!
Та й візьмися попід бочки.
Покажи нам свої скочки.
Та й візьмися попід пашки.
Шукай собі товаришки,
Та й візьмися попід плечі.
Покажи нам свої речі,
Та й притупни чобітками.
Золотими підківками...
Та й візьми гребінчика,
Розчеши русу косу
Ще й чорненькі брівця.','["pisni.org.ua", "cat:halycki", "cat:vesnyanky-hayivky", "Пісні з Галичини", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8184450'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8184450','Іванчику-білоданчику','Іванчику-білоданчику,
