INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8178312','До святої Вечері','Виконує: Анжела Вербицька','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'До святої Вечері
Кілька довгих годин,
До святої Вечері
Все життя, мов зітхання.
Народися, Ісусе,
І у серце прийди
Перша сходить зоря -
На землі вже світання.

Приспів:
А над Києвом срібний дзвін
Наполохає срібний сніг,
В монастир від тортурчих стін
Вели вночі на шлях, повір.
А дорога у храм кипить,
Хоч зима, світ не спить, не спить,
Світлу рясу вдягла блакить,
Бо вже перша зоря горить!

Тихо схлипує свічка,
Віск на руки сплива,
Почуй, Христе, у серці
Молитви слова.
Хай во ім''я Христа
Буде правда єдина!
Хай во ім''я Христа
Буде Україна!

Приспів. (2)

Перша зоря горить!
Перша зоря горить!','["pisni.org.ua", "cat:shchedrivky", "cat:suchasni-pisni-rizdvo", "Щедрівки", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8178312'), datetime('now')),datetime('now'));
