INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8185052','Купальська ніч','Музика: Леопольд Ященко Слова: Леопольд Ященко','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256',NULL,'А вже над плесом гаснуть вогні,
I замовка весела річ...
I буйні лози, й верби сумні
Оповила таємна ніч.

I гори над Дніпром
Заснули мирним сном...
I буйні лози, й верби сумні
Оповила таємна ніч.

I лиш єдиний вогник ясний
Ще мерехтить край бережка,
I хтось блукає в тиші німій,
I, мов сльоза, бринить ріка.

Речитатив:
- А може, то хлопець
Русалку виглядає?
Кажуть, що в таку ніч
Вони виходять на берег
І при місяці водять танок.

I хтось блукає в тиші німій,
I, мов сльоза, бринить ріка.

Купала на Йвана!
Озвися, де ти!
Прилинь, кохана!
I хтось блукає в тиші німій,
I, мов сльоза, бринить ріка.

Речитатив:
- А може, то він шукає
Цвіт папороті,
Який з''являється саме
В купальську ніч
І приносить щастя тому,
Хто його знайде?

I хтось блукає в тиші німій,
I, мов сльоза, бринить ріка.

Купала на Йвана!
Я буду ждать тебе
Всю ніч до рана!
I хтось блукає в тиші німій,
I, мов сльоза, бринить ріка... | (3)','["pisni.org.ua", "cat:kupalski", "Купальські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8185052'), datetime('now')),datetime('now'));
